/* 核心修复：限制弹窗高度并重构布局以支持内部滚动 */
#skill-detail-modal {
    max-height: 80vh !important;  /* 限制最大高度为视窗的80% */
    overflow: hidden !important;  /* 禁止弹窗整体出现滚动条 */
    display: flex !important;     /* 启用Flex布局 */
    flex-direction: column !important;
    padding: 0 !important;        /* 清除内边距，改由内部元素控制 */
}

/* 固定头部标题栏 */
#skill-detail-modal .item-detail-header {
    flex-shrink: 0;               /* 防止头部被压缩 */
    padding: 20px 25px 15px;      /* 补回内边距 */
    margin: 0;
    border-bottom: 1px solid var(--separator-color);
    background: inherit;          /* 保持背景一致 */
    z-index: 2;
}

/* 可滚动的内容区域 */
#skill-detail-content {
    flex-grow: 1;                 /* 占据剩余空间 */
    overflow-y: auto;             /* 内容过多时显示滚动条 */
    padding: 20px 25px 25px;      /* 补回内边距 */
    min-height: 0;                /* Flexbox 嵌套滚动的关键 */
    scrollbar-width: thin;        /* Firefox 细滚动条 */
}

/* 容器样式微调 */
.skill-detail-container {
    display: flex;
    flex-direction: column;
    gap: 15px;
    /* padding 已移除，由 #skill-detail-content 统一控制 */
}


/* 顶部徽章行 */
.skill-badge-row {
    display: flex;
    justify-content: center;
    gap: 10px;
    margin-bottom: 5px;
    flex-wrap: wrap;
}
.skill-badge {
    padding: 4px 12px;
    border-radius: 15px;
    font-size: 0.9em;
    font-weight: bold;
    color: #fff;
    box-shadow: 0 2px 5px rgba(0,0,0,0.3);
    text-shadow: 0 1px 2px rgba(0,0,0,0.5);
    border: 1px solid rgba(255,255,255,0.2);
}

/* 属性网格 */
.skill-stats-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
}
.skill-stat-box {
    background: rgba(0,0,0,0.25);
    border: 1px solid var(--separator-color);
    border-radius: 8px;
    padding: 10px;
    text-align: center;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    transition: transform 0.2s;
}
.skill-stat-box:hover {
    transform: translateY(-2px);
    border-color: var(--hover-color);
}
.skill-stat-label {
    font-size: 0.85em;
    color: var(--text-secondary);
    margin-bottom: 4px;
}
.skill-stat-val {
    font-weight: bold;
    color: var(--text-primary);
    font-size: 1em;
}

/* 内容文本块 */
.skill-desc-box, .skill-effect-box {
    background: rgba(255,255,255,0.03);
    border-radius: 8px;
    padding: 12px;
    border: 1px solid var(--separator-color);
    position: relative;
}
.skill-effect-box {
    border-left: 3px solid #66bb6a; /* 绿色左边框强调效果 */
}
.skill-box-title {
    font-size: 0.95em;
    color: #ffd700;
    margin-bottom: 8px;
    font-weight: bold;
    border-bottom: 1px dashed var(--separator-color);
    padding-bottom: 5px;
    display: flex;
    align-items: center;
    gap: 8px;
}
.skill-box-content {
    font-size: 0.95em;
    line-height: 1.6;
    color: #e0e0e0;
    white-space: pre-wrap;
    word-break: break-all;
}

/* 昼夜模式适配 */
body.theme-day .skill-stat-box {
    background: rgba(140, 90, 43, 0.08);
    border-color: #c1b7a4;
}
body.theme-day .skill-desc-box, body.theme-day .skill-effect-box {
