    flex-direction: column;
    flex-grow: 1;
    overflow: hidden; 
    position: relative;
    min-height: 0; /* 【关键修复】Flex容器嵌套滚动必须设置最小高度为0，否则会被内容撑开导致无法滚动 */
}

/* 顶部横向滚动导航栏 */
.sect-tabs {
    flex: 0 0 auto;
    display: flex;
    flex-direction: row;
    overflow-x: auto;
    background: rgba(20, 20, 20, 0.95);
    border-right: none;
    border-bottom: 2px solid #8c7853;
    padding: 0;
    scrollbar-width: thin;
    scrollbar-color: var(--primary-color) transparent;
    -ms-overflow-style: auto;
    z-index: 10;
}


/* 顶部横向滚动导航栏 */
.sect-tabs {
    flex: 0 0 auto;
    display: flex;
    flex-direction: row;
    overflow-x: auto;
    background: rgba(20, 20, 20, 0.95);
    border-right: none;
    border-bottom: 2px solid #8c7853;
    padding: 0;
    /* 隐藏导航栏滚动条但保持可滚动 */
    scrollbar-width: none; 
    -ms-overflow-style: none;
}
.sect-tabs::-webkit-scrollbar {
    height: 6px;
    background-color: transparent;
}

.sect-tabs::-webkit-scrollbar-track {
    background: rgba(0, 0, 0, 0.2);
    border-radius: 3px;
}

.sect-tabs::-webkit-scrollbar-thumb {
    background-color: var(--primary-color);
    border-radius: 3px;
}

.sect-tabs::-webkit-scrollbar-thumb:hover {
    background: var(--hover-color);
}

.sect-tab {
    padding: 15px 20px;
    cursor: pointer;
    border-left: 4px solid transparent;
    border-bottom: none;
    color: var(--text-secondary);
    transition: all 0.2s ease-in-out;
    display: flex;
    align-items: center;
    gap: 15px;
    font-size: 1.1em;
    opacity: 0.7;
    white-space: normal;
}


.sect-tab.active {
    background: rgba(0, 0, 0, 0.25);
    color: #ffd700;
    font-weight: bold;
    opacity: 1;
    text-shadow: none;
    border-bottom-color: transparent;
    border-left-color: var(--primary-color);
}


/* 内容区域 & 滚动条美化 */
.sect-tab-pane {
    display: none;
    flex-grow: 1;
    padding: 15px;
    overflow-y: auto; /* 开启垂直滚动 */
    -webkit-overflow-scrolling: touch; /* 【关键修复】iOS设备流畅滚动支持 */
    flex-direction: column;
    gap: 15px;
    background: rgba(0,0,0,0.2);
    padding-bottom: 50px; /* 底部留出更多空间防止遮挡 */
    min-height: 0; /* 【关键修复】配合父级flex布局防止溢出 */
    height: 100%; /* 【关键修复】强制填满剩余空间 */
}
