/* 任务列表美化 (New) */
.sect-task-card {
    border-left: 4px solid #5a4e3c;
    margin-bottom: 10px;
    transition: all 0.3s ease;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid #5a4e3c;
    border-radius: 8px;
}
.sect-task-card[data-status="available"] { border-left-color: #66bb6a; }
.sect-task-card[data-status="in-progress"] { border-left-color: #ffca28; }

/* --- 危险任务特效 (境界不足) --- */
.sect-task-card.danger-task {
    border-left-color: #d32f2f !important;
    border: 1px solid rgba(211, 47, 47, 0.4);
    box-shadow: inset 0 0 10px rgba(211, 47, 47, 0.1);
    animation: danger-breath 2s infinite alternate;
}
.sect-task-card.danger-task .sect-task-title { color: #ef5350; }
.sect-task-card.danger-task .sect-task-header:hover { background: rgba(211, 47, 47, 0.1) !important; }

@keyframes danger-breath {
    from { box-shadow: inset 0 0 5px rgba(211, 47, 47, 0.1); }
    to { box-shadow: inset 0 0 20px rgba(211, 47, 47, 0.25); }
}

/* 危险任务按钮样式 */
.danger-accept-btn {
    border-color: #d32f2f !important;
    color: #e57373 !important;
    background: transparent;
    transition: all 0.3s;
}
.danger-accept-btn:hover {
    background-color: #d32f2f !important;
    color: #fff !important;
    box-shadow: 0 0 15px #d32f2f;
}

/* === 新增：危险确认弹窗与破碎特效 === */
#danger-confirm-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0, 0, 0, 0.85);
    z-index: 20000;
    display: flex; justify-content: center; align-items: center;
    backdrop-filter: blur(5px);
    animation: fadeIn 0.3s ease;
}

.danger-confirm-box {
    width: 90%; max-width: 400px;
    background: linear-gradient(145deg, #1a0000, #2a0a0a);
    border: 2px solid #ef5350;
    box-shadow: 0 0 30px rgba(239, 83, 80, 0.4), inset 0 0 20px rgba(0,0,0,0.8);
    padding: 25px;
    border-radius: 8px;
    text-align: center;
    position: relative;
    transform: scale(1);
    transition: transform 0.1s;
}

/* 警告标题 */
.danger-title {
    color: #ff5252; font-size: 1.8em; font-weight: bold; margin-bottom: 15px;
    text-shadow: 0 0 10px rgba(255, 0, 0, 0.8);
    animation: danger-shake 0.5s infinite; /* 微微颤抖 */
}

/* 破碎动画关键帧 */
@keyframes shatter-effect {
    0% { transform: scale(1) rotate(0deg); opacity: 1; filter: brightness(1); }
    20% { transform: scale(1.1) rotate(-2deg); opacity: 1; filter: brightness(2); } /* 聚能高亮 */
    40% { transform: scale(1.05) rotate(2deg) skew(10deg); opacity: 0.9; }
    100% { transform: scale(1.5) rotate(0deg); opacity: 0; filter: blur(10px); } /* 炸裂消失 */
}

/* 应用破碎类 */
.danger-confirm-box.shattering {
    animation: shatter-effect 0.4s forwards ease-out;
    pointer-events: none;
}

@keyframes danger-shake {
    0%, 100% { transform: translateX(0); }
    25% { transform: translateX(-1px); }
    75% { transform: translateX(1px); }
}


