/* --- 小地图控制条样式 --- */
#mini-map-controls {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 30px;
    background: rgba(0, 0, 0, 0.6);
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 10px;
    box-sizing: border-box;
    border-top: 1px solid var(--separator-color);
    z-index: 20; /* 确保在画布之上 */
    opacity: 0; /* 默认隐藏，鼠标悬停显示 */
    transition: opacity 0.3s;
}

#mini-map-container:hover #mini-map-controls {
    opacity: 1;
}

#mini-map-size-slider {
    width: 100%;
    height: 4px;
    -webkit-appearance: none;
    background: rgba(255, 255, 255, 0.3);
    border-radius: 2px;
    outline: none;
    cursor: pointer;
}

#mini-map-size-slider::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: #ffd700;
    cursor: pointer;
    box-shadow: 0 0 5px rgba(0,0,0,0.5);
}
#mini-map-container {
    transition: transform 0.3s ease-in-out;
}

#mini-map-container.retracted-left {
    transform: translateX(calc(-100% + 20px));
}
#mini-map-container.retracted-right {
    transform: translateX(calc(100% - 20px));
}
#mini-map-container.retracted-top {
    transform: translateY(calc(-100% + 20px));
}
#mini-map-container.retracted-bottom {
    transform: translateY(calc(100% - 20px));
}

#mini-map-container::after {
    content: '\f359';
    font-family: 'Font Awesome 5 Free';
    font-weight: 900;
    position: absolute;
    background-color: rgba(0, 0, 0, 0.6);
    color: var(--primary-color);
    border: 1px solid var(--separator-color);
    width: 20px;
    height: 40px;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    opacity: 0;
    transition: opacity 0.3s;
    pointer-events: none;
}

#mini-map-container.retracted-left::after {
    opacity: 1; pointer-events: auto;
    right: -21px; top: 50%;
    transform: translateY(-50%);
    border-radius: 0 8px 8px 0;
    content: '\f35a';
}
#mini-map-container.retracted-right::after {
    opacity: 1; pointer-events: auto;
    left: -21px; top: 50%;
    transform: translateY(-50%);
    border-radius: 8px 0 0 8px;
    content: '\f359';
}
#mini-map-container.retracted-top::after {
    opacity: 1; pointer-events: auto;
    bottom: -21px; left: 50%;
    transform: translateX(-50%);
    width: 40px; height: 20px;
    border-radius: 0 0 8px 8px;
    content: '\f358';
}
#mini-map-container.retracted-bottom::after {
    opacity: 1; pointer-events: auto;
    top: -21px; left: 50%;
    transform: translateX(-50%);
    width: 40px; height: 20px;
    border-radius: 8px 8px 0 0;
    content: '\f35b';
}


