/* 顶部工具栏：左右分栏布局 */
.thinking-header-bar {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 0 0 10px;
    background: rgba(0, 0, 0, 0.4);
    border-bottom: 1px solid var(--separator-color);
    height: 50px;
}

/* 左侧：Tabs 滚动容器 */
.thinking-log-tabs {
    flex: 1;
    min-width: 0; /* 关键：允许Flex子项收缩以产生滚动 */
    display: flex;
    align-items: center;
    gap: 8px;
    overflow-x: auto; /* 开启横向滚动 */
    overflow-y: hidden;
    white-space: nowrap;
    height: 100%;
    padding-right: 10px;
    /* 隐藏滚动条但保留功能 */
    scrollbar-width: none; 
    -ms-overflow-style: none;
}
.thinking-log-tabs::-webkit-scrollbar { display: none; }

/* Tab 样式 */
.thinking-log-tab {
    flex-shrink: 0; /* 防止Tab被压缩 */
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255,255,255,0.1);
    color: #aaa;
    padding: 6px 14px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 0.9em;
    transition: all 0.2s;
}
/* 【修复】选中状态高对比度：深色背景+白色文字 */
.thinking-log-tab.active {
    background-color: var(--primary-color) !important;
    color: #ffffff !important;
    font-weight: bold;
    border-color: transparent;
    box-shadow: 0 0 8px rgba(255, 215, 0, 0.4);
}

/* 右侧：固定操作区 (修复版：统一背景色) */
.thinking-window-actions {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    height: 100%;
    padding: 0 10px;
    /* 移除渐变，改为透明或与左侧一致的背景，这里用透明即可，因为父容器已有背景 */
    background: transparent; 
    /* 既然颜色统一了，竖线也可以选择移除或保留，建议保留一根淡淡的线作为功能区分 */
    border-left: 1px solid rgba(255,255,255,0.1); 
}


.thinking-action-btn {
    background: rgba(0,0,0,0.3);
    border: 1px solid var(--separator-color);
    color: #ccc;
    width: 32px;
    height: 32px;
    border-radius: 6px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-left: 8px;
    transition: all 0.2s;
}
.thinking-action-btn:hover {
    background: var(--primary-color);
    color: #1a1a1a;
}
#close-thinking-popup-btn:hover {
    background: #e57373;
    color: white;
    border-color: #e57373;
}

/* 内容区域 */
.thinking-log-tab-content {
    display: none;
    flex-grow: 1;
    padding: 15px;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
}
.thinking-log-tab-content.active { display: block; }
/* 内容文本区域优化 */
#thinking-log-popup pre {
    white-space: pre-wrap;
    word-wrap: break-word;
    margin: 0;
    font-family: 'Consolas', 'Monaco', monospace;
    font-size: 0.95em;
    line-height: 1.6;
    color: #d4d4d4;

    /* --- 核心修复：优化选词体验 --- */
    cursor: text; /* 鼠标变为文本输入状 */
    user-select: text !important; /* 强制允许选择文本 */
    -webkit-user-select: text !important; /* Safari/Chrome 兼容 */
    -moz-user-select: text !important;

    /* 允许垂直滚动，防止触摸事件被拦截导致无法选择 */
    touch-action: pan-y; 

    /* 增加底部留白，防止文字贴底难选中 */
    padding-bottom: 40px; 
}.icon-button {
    background: none;
    border: none;
    color: #ccc;
    cursor: pointer;
    font-size: 16px;
    padding: 5px 8px;
    border-radius: 4px;
    transition: background-color 0.2s, color 0.2s;
}
.icon-button:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}
.icon-button.danger:hover {
    background-color: rgba(229, 115, 115, 0.2);
    color: #e57373;
}
.dressing-room-layout { display: flex; height: 100%; gap: 15px; }
.dressing-preview { 
    flex: 1; 
    background: url('https://www.transparenttextures.com/patterns/dark-matter.png') #222; 
    border: 1px solid #5a4e3c; 
    border-radius: 8px; 
    position: relative; 
    overflow: hidden; 
    display: flex; justify-content: center; align-items: center;
}
.dressing-controls { flex: 1; display: flex; flex-direction: column; gap: 10px; min-width: 0; height: 100%; overflow: hidden; }
.dressing-tabs { display: flex; gap: 5px; border-bottom: 2px solid #5a4e3c; padding-bottom: 5px; }
.dressing-tab { 
    flex: 1; padding: 8px; 
    background: rgba(0,0,0,0.3); border: 1px solid #5a4e3c; color: #aaa; 
    cursor: pointer; text-align: center; border-radius: 5px 5px 0 0; 
}
.dressing-tab.active { background: #8c7853; color: #1a1a1a; font-weight: bold; border-color: #ffd700; }
.resource-grid { 
    flex-grow: 1; 
    display: grid; grid-template-columns: repeat(auto-fill, minmax(70px, 1fr)); 
    gap: 8px; 
    overflow-y: auto; min-height: 0; 
    align-content: start;
    background: rgba(0,0,0,0.2); padding: 8px; border-radius: 4px; 
}
.resource-item { 
    aspect-ratio: 1; border: 1px solid #5a4e3c; border-radius: 4px; 
    cursor: pointer; overflow: hidden; position: relative; 
    background: #333; transition: all 0.2s;
}
.resource-item:hover, .resource-item.selected { border-color: #ffd700; transform: scale(1.05); }
.resource-item img { width: 100%; height: 100%; object-fit: contain; }
.adjust-controls { display: flex; flex-direction: column; gap: 8px; padding: 10px; background: rgba(0,0,0,0.2); border-radius: 4px; }
.slider-row { display: flex; align-items: center; gap: 10px; font-size: 0.8em; }
.slider-row label { width: 60px; color: #ccc; }
.slider-row input { flex-grow: 1; }
@media (max-width: 768px) {
    .dressing-room-layout { flex-direction: column; overflow: hidden; }
    .dressing-preview { height: 35%; flex: none; }
    .dressing-controls { flex: 1; min-height: 0; overflow: hidden; }
}
.item-detail-modal {
background-image: url('https://www.transparenttextures.com/patterns/dark-leather.png');
background-color: #2b2b2b;
border: 1px solid #8c7853;
box-shadow: 0 0 30px rgba(0, 0, 0, 0.8);
padding: 0 !important;
overflow: hidden;
display: flex;
flex-direction: column;
max-height: 85vh;
border-radius: 8px;
}
.dice-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(circle, rgba(0, 0, 0, 0.6) 0%, rgba(0, 0, 0, 0.9) 100%);
    display: none;
    align-items: center;
    justify-content: center;
    z-index: 9999;
    opacity: 0;
    backdrop-filter: blur(8px);
    transition: opacity 0.3s ease-in-out;
}

.dice-overlay.visible {
    display: flex;
    opacity: 1;
}

#d20-container {
    position: relative;
    overflow: visible;
    transition: transform 0.3s ease, margin-bottom 0.3s ease;
}

#d20-svg {
    filter: drop-shadow(0 0 8px rgba(255, 215, 0, 0.3));
    overflow: visible;
}

#d20-svg text {
    cursor: default;
    user-select: none;
    font-family: 'Ma Shan Zheng', 'ZCOOL XiaoWei', serif;
}

#d20-svg .trigram {
    font-size: 24px;
    fill: #ffd700;
    font-weight: bold;
    filter: drop-shadow(0 0 5px rgba(255, 140, 0, 0.8));
}

#d20-svg .stem-branch {
    font-size: 14px;
    fill: #ffffff;
    font-weight: bold;
    opacity: 0.8; 
    filter: drop-shadow(0 0 2px rgba(0, 0, 0, 1));
}

/* 太极旋转动画 */
@keyframes taiji-spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

#taiji {
    animation: taiji-spin 10s linear infinite;
    transform-box: fill-box;
    transform-origin: center;
    filter: url(#taiji-glow);
}

#d20-center-display circle {
    stroke: #ffd700;
    stroke-width: 1.5;
    filter: drop-shadow(0 0 5px rgba(255, 215, 0, 0.5));
}

/* 大吉特效：神圣金光呼吸 */
@keyframes critical-gold-pulse {
    0% { filter: drop-shadow(0 0 5px #ffd700); transform: scale(1); }
    50% { filter: drop-shadow(0 0 25px #ffd700) drop-shadow(0 0 10px #fff); transform: scale(1.3); }
    100% { filter: drop-shadow(0 0 5px #ffd700); transform: scale(1); }
}

/* 大凶特效：血色颤抖故障 */
@keyframes critical-blood-shake {
    0% { filter: drop-shadow(0 0 5px #ff0000); transform: translate(0,0) scale(1); }
    20% { transform: translate(-2px, 2px) scale(1.2); }
    40% { transform: translate(2px, -2px) scale(1.2); filter: drop-shadow(0 0 30px #ff0000); }
    60% { transform: translate(-3px, 0) scale(1.2); }
    80% { transform: translate(3px, 2px) scale(1.2); }
    100% { filter: drop-shadow(0 0 5px #ff0000); transform: translate(0,0) scale(1); }
}

.crit-visual-success {
    animation: critical-gold-pulse 1.5s infinite ease-in-out !important;
    fill: #fff700 !important;
    transform-box: fill-box;
    transform-origin: center;
}

.crit-visual-fail {
    animation: critical-blood-shake 0.4s infinite linear !important;
    fill: #ff3333 !important;
    transform-box: fill-box;
    transform-origin: center;
}

/* 投掷时的入场动画 */
#d20-container.rolling #d20-rings,
#d20-container.rolling #d20-center-display {
    animation: fade-in-scale-up 1s cubic-bezier(0.165, 0.84, 0.44, 1) forwards;
}

/* 罗盘外环顺时针旋转 */
#d20-container.rolling #ring-outer {
    transform-origin: 100px 100px;
    animation-name: spin-clockwise;
    animation-duration: 2.5s;
    animation-timing-function: cubic-bezier(0.2, 0.8, 0.2, 1);
    animation-fill-mode: forwards;
}

/* 罗盘中环逆时针旋转 */
#d20-container.rolling #ring-middle {
    transform-origin: 100px 100px;
    animation-name: spin-counter-clockwise;
    animation-duration: 2.3s;
    animation-timing-function: cubic-bezier(0.3, 0.9, 0.3, 1);
    animation-fill-mode: forwards;
}

@keyframes fade-in-scale-up {
    from { opacity: 0; transform: scale(0.6); }
    to { opacity: 1; transform: scale(1); }
}

@keyframes spin-clockwise {
    from { transform: rotate(0deg); }
    to { transform: rotate(1080deg); }
}

@keyframes spin-counter-clockwise {
    from { transform: rotate(0deg); }
    to { transform: rotate(-720deg); }
}

/* 结果数字显示 */
#d20-number {
    opacity: 0;
    font-size: 44px;
    font-family: 'Ma Shan Zheng', cursive;
    font-weight: bold;
    text-anchor: middle;
    dominant-baseline: middle;
}

#d20-container.rolling #d20-number {
    animation: number-show 0.8s 1.8s forwards;
}

@keyframes number-show {
    from { opacity: 0; filter: blur(8px); transform: scale(3); }
    to { opacity: 1; filter: blur(0); transform: scale(1); }
}

/* 底部结果文字 */
/* --- 结果文字容器基础样式 --- */
.dice-result-text {
    position: absolute;
    bottom: 20%; /* 从原来的计算值改为百分比，适配不同长宽比屏幕 */
    left: 0;
    width: 100%;
    text-align: center;
    z-index: 10001;
    opacity: 0;
    transform: translateY(20px) scale(0.9);
    transition: opacity 0.5s 0.2s ease-out, transform 0.5s 0.2s ease-out;
    pointer-events: none;

    /* 默认字体大小 (桌面端) */
    font-size: 16px; 
}

.dice-result-text.visible {
    opacity: 1;
    transform: translateY(0) scale(1);
}

/* --- 核心：手机端适配 --- */
@media (max-width: 768px) {
    .dice-result-text {
        bottom: 25%; /* 手机上稍微靠上一点 */
    }

    /* 调整罗盘容器在手机上的位置，防止遮挡 */
    #d20-container {
        margin-bottom: 60px !important; /* 覆盖JS的内联样式 */
    }
}

/* 战斗标志 */
#combat-indicator {
    position: absolute;
    top: -100px;
    left: 50%;
    transform: translateX(-50%);
    color: #ff2a2a;
    font-family: 'Ma Shan Zheng', cursive;
    font-size: 3em;
    font-weight: bold;
    text-shadow: 0 0 10px #000, 0 0 20px #8b0000, 0 0 30px #ff0000;
    white-space: nowrap;
    pointer-events: none;
    display: none;
    z-index: 10005;
}

#combat-indicator.visible {
    display: block;
    animation: combat-shock 0.5s infinite alternate;
}

@keyframes combat-shock {
    0% { transform: translateX(-50%) scale(1); text-shadow: 0 0 10px #000, 0 0 20px #8b0000; }
    100% { transform: translateX(-50%) scale(1.1); text-shadow: 0 0 10px #000, 0 0 30px #ff0000, 0 0 50px #ff0000; }
}

