};

function getSectUpgradeCost(currentLevel) {
    const nextLevel = currentLevel + 1;
    if (nextLevel > UPGRADE_CONFIG.sect.getMaxLevel()) {
        return null;
    }
    const prestige = Math.floor(UPGRADE_CONFIG.sect.basePrestige * Math.pow(UPGRADE_CONFIG.sect.prestigeMultiplier, currentLevel));
    const funds = Math.floor(UPGRADE_CONFIG.sect.baseFunds * Math.pow(UPGRADE_CONFIG.sect.fundsMultiplier, currentLevel));
    return { level: nextLevel, prestige, funds };
}

function getBuildingUpgradeCost(currentLevel, buildingType = 'default') {
    const nextLevel = currentLevel + 1;
    if (nextLevel > UPGRADE_CONFIG.building.getMaxLevel(buildingType)) {
        return null;
    }
    const baseFund = UPGRADE_CONFIG.building.baseFunds[Math.min(currentLevel, UPGRADE_CONFIG.building.baseFunds.length - 1)];
    const funds = Math.floor(baseFund * Math.pow(UPGRADE_CONFIG.building.fundsMultiplier, currentLevel));
    return { level: nextLevel, funds };
}

