                    <div style="font-size: 0.9em; color: var(--text-secondary);">周期营收</div>
                    <div style="font-size: 1.1em; color: #ffd700; margin-top: 4px;">
                        ${income} <small>灵石</small> ${changeHtml}
                    </div>
                </div>
            </div>
        `;
    });

    gridHtml += '</div>';

    container.innerHTML = `<div style="flex-grow: 1; overflow-y: auto; min-height: 0;">${gridHtml}</div>`;
}


function renderSectHerbGarden(herbGardenData, container) {
    if (!container) return;

    if (container.intervalId) {
        clearInterval(container.intervalId);
    }

    const playerPosition = currentState.sectData?.positions?.find(p => p.members?.includes('B1'));
    let canManage = false;
    if (playerPosition) {
        const superAdminTitles = ['宗主', '太上长老', '副宗主'];
        canManage = playerPosition.permissions?.includes('all') || 
                    playerPosition.permissions?.includes('manage_herb_garden') ||
                    superAdminTitles.includes(playerPosition.title);
    }

    let buttonHtml = '';
    if (canManage) {
        buttonHtml = `
            <div style="text-align: right; margin-bottom: 10px; flex-shrink: 0;">
                <button id="plant-new-herb-btn" class="major-action-button small-font-btn">
                    <i class="fas fa-seedling"></i> 种植药草
                </button>
            </div>
        `;
    }

    const herbs = herbGardenData || [];

    const groupedHerbs = herbs.reduce((acc, herb) => {
        const key = herb.name;
        if (!acc[key]) {
            acc[key] = { ...herb, count: 0, instances: [] };
        }
        acc[key].count += (herb.count || 1);
        acc[key].instances.push(herb);
        return acc;
    }, {});


    if (Object.keys(groupedHerbs).length === 0) {
        container.innerHTML = buttonHtml + '<div style="flex-grow: 1; display: flex; align-items: center; justify-content: center; color: var(--text-secondary);">药园空空如也，快去种点什么吧。</div>';
    } else {
        let gridHtml = '<div class="herb-garden-grid">';
        for (const groupName in groupedHerbs) {
            const group = groupedHerbs[groupName];
            const representativeHerb = group.instances[0];

            // 兼容存档字段: plantedAt (时间), cycle (天数), phase (阶段)
            const pTimeVal = representativeHerb.plantingTime || representativeHerb.plantedAt;

            // 【修复】增强的时间解析逻辑 (解决 NaN% 问题)
            let pDate = null;
            if (typeof parseGameTime === 'function') {
                pDate = parseGameTime(pTimeVal);
            }

            // 如果 parseGameTime 失败或未定义，尝试手动正则解析 "XXXX年XX月XX日"
            if (!pDate || isNaN(pDate.getTime())) {
                const match = (pTimeVal || '').toString().match(/(\d+)年\s*(\d+)月\s*(\d+)日/);
                if (match) {
                    // 构造 Date 对象 (月份从0开始)
                    pDate = new Date(parseInt(match[1]), parseInt(match[2]) - 1, parseInt(match[3]));
                } else {
                    pDate = new Date(pTimeVal);
                }
            }

            // 兜底：如果仍然无效，默认为当前时间，防止计算崩溃
            if (!pDate || isNaN(pDate.getTime())) {
                console.warn('药园时间解析失败:', pTimeVal);
                pDate = new Date(); 
            }

            const plantingTime = pDate.getTime();


            // 周期转换：如果有 maturityCycleHours 直接用，否则检查 cycle (通常是天数，转为小时)

            const cycleHours = representativeHerb.maturityCycleHours || (representativeHerb.cycle ? representativeHerb.cycle * 24 : 24);
            const maturityCycleMs = cycleHours * 60 * 60 * 1000;

            const now = Date.now();
            const elapsedTime = now - plantingTime;
            const maturityRate = Math.min(100, (elapsedTime / maturityCycleMs) * 100);

            const remainingMs = Math.max(0, maturityCycleMs - elapsedTime);
            const hours = Math.floor(remainingMs / (1000 * 60 * 60));
            const minutes = Math.floor((remainingMs % (1000 * 60 * 60)) / (1000 * 60));
            const remainingTimeStr = hours > 0 ? `${hours}时${minutes}分` : `${minutes}分钟`;

            const stageInfo = representativeHerb.currentStage || representativeHerb.phase || '生长中';
            const stageColor = maturityRate >= 100 ? '#66bb6a' : '#ffd700';

            gridHtml += `
            <div class="herb-card" data-herb-name="${groupName}">
                <canvas id="herb-canvas-${groupName.replace(/\s/g, '')}" class="herb-card-icon" width="64" height="64"></canvas>
                <div class="herb-card-main">
                    <div style="font-weight: bold; display: flex; justify-content: space-between;">
                        <span>${groupName}</span>
                        <span style="color: #ccc; font-size: 0.9em;">x ${group.count}</span>
                    </div>
                    <div class="herb-progress-bar">
                        <div class="herb-progress-fill" style="width: ${maturityRate.toFixed(1)}%;"></div>
                        <div class="herb-progress-text">${maturityRate.toFixed(1)}%</div>
                    </div>
                    <div style="font-size: 0.8em; color: #aaa; text-align: center; margin-top: 4px;">
                        ${maturityRate < 100 ? `剩余: ${remainingTimeStr}` : `<span style="color:${stageColor};">已成熟</span>`} | 阶段: <span style="color:${stageColor};">${stageInfo}</span>
                    </div>
                    ${maturityRate >= 100 ? `<button class="major-action-button harvest-herb-btn" data-herb-name="${groupName}" style="margin-top: 8px;">采摘一株</button>` : `<div style="height: 33px;"></div>`}
                </div>
            </div>`;
        }
        gridHtml += '</div>';
        container.innerHTML = buttonHtml + `<div style="flex-grow: 1; overflow-y: auto; min-height: 0;">${gridHtml}</div>`;

        for (const groupName in groupedHerbs) {
            const canvas = document.getElementById(`herb-canvas-${groupName.replace(/\s/g, '')}`);
            const representativeHerb = groupedHerbs[groupName].instances[0];

            if (canvas && representativeHerb.growthStages) {
                const pTimeVal = representativeHerb.plantingTime || representativeHerb.plantedAt;
                const plantingTime = new Date(pTimeVal).getTime();
                const cycleHours = representativeHerb.maturityCycleHours || (representativeHerb.cycle ? representativeHerb.cycle * 24 : 24);
                const maturityCycleMs = cycleHours * 60 * 60 * 1000;

                const now = Date.now();
                const elapsedTime = now - plantingTime;
                const maturityRate = Math.min(100, (elapsedTime / maturityCycleMs) * 100);

                let currentStage = representativeHerb.growthStages
                    .slice()
                    .sort((a, b) => b.threshold - a.threshold)
                    .find(stage => maturityRate >= stage.threshold);

                if (currentStage && currentStage.pixelData) {
                    drawPixelArt(canvas, currentStage.pixelData);
                }
            }
        }
    }

    container.intervalId = setInterval(() => {
        if (!document.body.contains(container)) {
            clearInterval(container.intervalId);
            return;
        }
        renderSectHerbGarden(currentState.sectData?.herbGarden || [], container);
    }, 60000);
}
