            prevVal = prevRemarks[field.subkey];
            latestVal = latestRemarks[field.subkey];
        } else if (field.key === '2' && (field.subkey === 'realm' || field.subkey === 'identity')) {
            const prevParts = ((prevData && prevData['2']) || '|').split('|');
            const latestParts = ((latestData && latestData['2']) || '|').split('|');
            prevVal = field.subkey === 'realm' ? prevParts[0] : prevParts[1];
            latestVal = field.subkey === 'realm' ? latestParts[0] : latestParts[1];
        } else if (field.key === '16' && field.subkey === 'location') {
            const prevVisuals = ((prevData && prevData['16']) || '||||').split('|');
            const latestVisuals = ((latestData && latestData['16']) || '||||').split('|');
            prevVal = prevVisuals[2];
            latestVal = latestVisuals[2];
        } else {
            prevVal = prevData ? prevData[field.key] : undefined;
            latestVal = latestData[field.key];
        }

        addChange(field.label, prevVal, latestVal);
    });

    try {
        const prevAttrs = JSON.parse(prevData ? prevData['11'] : '{}' || '{}');
        const latestAttrs = JSON.parse(latestData['11'] || '{}');
        const attrKeys = new Set([...Object.keys(prevAttrs), ...Object.keys(latestAttrs)]);

        attrKeys.forEach(key => {
            const pa = prevAttrs[key];
            const la = latestAttrs[key];
            if (pa && la && (pa.current !== la.current || pa.max !== la.max)) {
                const prevStr = `${pa.current}/${pa.max}`;
                const latestStr = `${la.current}/${la.max}`;
                addChange(key, prevStr, latestStr);
            } else if (!pa && la) {
                 addChange(key, '无', `${la.current}/${la.max}`);
            }
        });
    } catch(e) {}

    const prevBio = (prevData && prevData['35']) ? prevData['35'] : '';
    const latestBio = latestData['35'] || '';
    if (latestBio && prevBio !== latestBio) {
        const newText = latestBio.replace(prevBio, '').trim();
        if (newText) {
             changes += `<li><span class="label">新增生平:</span> ${newText.replace(/\n/g, '<br>')}</li>`;
        }
    }

    return changes;
}

function parseNestedJsonString(str, fallback = []) {
    if (typeof str !== 'string' || !str) {
        if (typeof str === 'object' && str !== null) return str;
        return Array.isArray(fallback) ? [...fallback] : fallback;
    }
    let current = str;
    for (let i = 0; i < 3; i++) {
        if (typeof current !== 'string') return current;
        let tempStr = current.trim();
        try {
            const parsed = JSON.parse(tempStr);
            current = parsed;
            continue;
        } catch (e) {
        }
        if ((tempStr.startsWith('"') && tempStr.endsWith('"')) || (tempStr.startsWith("'") && tempStr.endsWith("'"))) {
            tempStr = tempStr.substring(1, tempStr.length - 1);
        }
        try {
             const fixedSingleQuote = tempStr.replace(/'/g, '"');
             const parsed = JSON.parse(fixedSingleQuote);
             current = parsed;
             continue;
        } catch(e) {}
        break;
    }
    if (typeof current === 'object' && current !== null) {
        return current;
    }
    return Array.isArray(fallback) ? [...fallback] : fallback;
}

function recursivelyParseJsonStrings(data) {
    if (typeof data === 'string') {
        const trimmedString = data.trim();
        // 只有看起来像 JSON 对象或数组字符串时才尝试解析
        if ((trimmedString.startsWith('{') && trimmedString.endsWith('}')) || (trimmedString.startsWith('[') && trimmedString.endsWith(']'))) {
            // 1. 优先标准解析
            try {
                const parsedData = JSON.parse(trimmedString);
                return recursivelyParseJsonStrings(parsedData);
            } catch (e) {
                // 2. 标准解析失败，尝试修复单引号 (常见错误 {'a':1})
                try {
                     // 简单的单引号替换，可能会误伤内容中的单引号，但在处理AI生成的非标JSON时通常必要
                    const validJsonString = trimmedString.replace(/'/g, '"');
                    const parsedData = JSON.parse(validJsonString);
                    return recursivelyParseJsonStrings(parsedData);
                } catch (e2) {
                    // 3. 尝试修复转义引号 (常见错误 "{\"a\"}") 
                    // 注意：这会破坏 HTML 属性中的引号，但如果到了这一步说明标准解析已经挂了，只能试一试
                    try {
                         const fixedEscape = trimmedString.replace(/\\"/g, '"');
                         const parsedData = JSON.parse(fixedEscape);
                         return recursivelyParseJsonStrings(parsedData);
                    } catch(e3) {
                        // 实在解析不了，返回原字符串，避免报错中断流程
                        // console.warn(`recursivelyParseJsonStrings 解析失败，保留原值:`, data);
                        return data;
                    }
                }
            }
        }
    } 
    else if (Array.isArray(data)) {
        return data.map(item => recursivelyParseJsonStrings(item));
    } 
    else if (typeof data === 'object' && data !== null) {
        for (const key in data) {
            if (Object.hasOwnProperty.call(data, key)) {
                data[key] = recursivelyParseJsonStrings(data[key]);
            }
        }
    }
    return data;
}
function extractJsonArrayFromString(rawString) {
    if (!rawString || typeof rawString !== 'string') {
        return null;
    }

    const codeBlockRegex = /```(?:json|worldbook)?\s*([\s\S]*?)\s*```/g;
    let matches = [];
    let match;

    while ((match = codeBlockRegex.exec(rawString)) !== null) {
        matches.push(match[1].trim());
    }

    if (matches.length > 0) {
        if (matches.length === 1) {
            const singleBlockContent = matches[0];
            if (singleBlockContent.startsWith('[') && singleBlockContent.endsWith(']')) {
                try {
                    JSON.parse(singleBlockContent);
                    return singleBlockContent;
                } catch (e) {
                    // It might be a single object wrapped in blocks
                }
            }
        }

        try {
            const combinedArrayString = `[${matches.join(',')}]`;
            JSON.parse(combinedArrayString);
            return combinedArrayString;
        } catch (e) {
            console.warn("合并多个JSON块后解析失败:", e);

            return null;
        }
    }

    const firstBracket = rawString.indexOf('[');
    const lastBracket = rawString.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket > firstBracket) {
        const potentialJson = rawString.substring(firstBracket, lastBracket + 1);
        try {
            JSON.parse(potentialJson);
            return potentialJson;
        } catch (e) {
            // final fallback failed
        }
    }

    return null;
}

function parseTableEditCommands(commandsString, errorMessages = []) {
    console.log("【步骤1: 进入 parseTableEditCommands】开始解析指令字符串...");
    console.log("原始指令字符串:", commandsString);
    const delta = [];
    let smallSummary = null;
    let largeSummary = null;

    if (typeof commandsString !== 'string') {
        errorMessages.push({ title: "指令格式错误", details: "传入的指令不是一个有效的字符串。" });
        console.error("【中断】指令不是字符串，解析终止。");
        return { delta, smallSummary, largeSummary };
    }

    const sanitizedCommandsString = commandsString.replace(/\\(?!["\\/bfnrtu])/g, '\\\\');
    const commands = extractCommands(sanitizedCommandsString);
    console.log(`【步骤1.1】成功提取到 ${commands.length} 条指令。`);

    commands.forEach((commandStr, index) => {
        console.log(`--- 开始处理第 ${index + 1} 条指令: ${commandStr} ---`);
        let match = commandStr.match(/^(\w+)\(([\s\S]*)\)$/);
        if (!match) {
            errorMessages.push({ title: "指令基本格式错误", details: `无法解析指令 "${commandStr}"。` });
            console.error(`【中断】第 ${index + 1} 条指令格式不匹配，跳过。`);
            return;
        }

        let command = match[1];
        let argsString = match[2].trim();

        try {
            const args = [];
            if (argsString) {
                let depth = 0;
                let lastSplit = 0;
                let inString = false;
                for (let i = 0; i < argsString.length; i++) {
                    const char = argsString[i];
                    if (char === '"' && (i === 0 || argsString[i-1] !== '\\')) {
                        inString = !inString;
                    }
                    if (!inString) {
                         if (char === '{' || char === '[' || char === '(') depth++;
                         if (char === '}' || char === ']' || char === ')') depth--;
                    }
                    if (char === ',' && depth === 0 && !inString) {
                        args.push(JSON.parse(argsString.substring(lastSplit, i).trim()));
                        lastSplit = i + 1;
                    }
                }
                args.push(JSON.parse(argsString.substring(lastSplit).trim()));
            }

            if(command === 'set' && args.length === 2 && typeof args[0] === 'string') {
                console.warn(`[指令修正] 检测到不规范的 set("${args[0]}", ...) 指令，已自动修正为 add 指令。`);
                command = 'add';
            }

            let data, id, attribute, value, slot, item;
            switch (command) {
                case 'set':
                    if (args.length === 1 && typeof args[0] === 'object') {
                        data = recursivelyParseJsonStrings(args[0]);
                        delta.push({ command, data });
                        console.log(`【步骤1.2】解析成功: set 指令, 数据:`, data);
                    } else {
                        throw new Error(`指令 "set" 的参数格式不正确，应为 set({...})。`);
                    }
                    break;
                case 'add':
                    id = args[0];
                    data = recursivelyParseJsonStrings(args[1]);
                    delta.push({ command, id, data });
                    console.log(`【步骤1.2】解析成功: add 指令, ID: ${id}, 数据:`, data);
                    break;
                case 'addSmallSummary':
                    smallSummary = args[0];
                    console.log(`【步骤1.2】解析成功: addSmallSummary`);
                    break;
                case 'addLargeSummary':
                    largeSummary = args[0];
                    console.log(`【步骤1.2】解析成功: addLargeSummary`);
                    break;
                case 'de':
                    id = args[0];
                   const subCategory = args[1]; 
                   const subId = args[2]; 
                   delta.push({ command, id, subCategory, subId });
                   console.log(`【步骤1.2】解析成功: de 指令, ID: ${id}, 子类: ${subCategory || '无'}, 子ID: ${subId || '无'}`);
                   break;
                case 'addWorldEvent':
                    delta.push({ command: 'addWorldEvent', eventData: { "0": args[0], "1": args[1], "2": args.length > 2 ? args.slice(2).join(', ') : ''} });
                    if (args.length < 3) { console.warn("addWorldEvent指令参数不足"); }
                    console.log(`【步骤1.2】解析成功: addWorldEvent`);
                    break;
                case 'updateAttribute':
                    id = args[0];
                    attribute = args[1];
                    value = args[2];
                    delta.push({ command, id, attribute, value });
                    console.log(`【步骤1.2】解析成功: updateAttribute, ID: ${id}, 属性: ${attribute}`);
                    break;
                case 'equipItem':
                case 'unequipItem':
                    id = args[0];
                    slot = args[1];
                    item = args[2];
                    delta.push({ command, id, slot, item });
                    console.log(`【步骤1.2】解析成功: ${command}, ID: ${id}, 槽位: ${slot}`);
                    break;
                case 'createLocation':
                    delta.push({ command: 'createLocation', locationData: args[0] });
                     console.log(`【步骤1.2】解析成功: createLocation`);
                    break;
                case 'updateRegion':
                    delta.push({ command: 'updateRegion', regionData: args[0] });
                     console.log(`【步骤1.2】解析成功: updateRegion`);
                    break;
                case 'deleteLocation':
                    delta.push({ command: 'deleteLocation', locationId: args[0]});
                     console.log(`【步骤1.2】解析成功: deleteLocation`);
                    break;
                default:
                    throw new Error(`未知的指令类型 "${command}"`);
            }
        } catch (e) {

errorMessages.push({
title: `指令 "${command}" 解析失败`,
details: `出错指令: ${commandStr}\n\n错误原因: ${e.message}\n\n请检查括号内的JSON格式是否正确（如引号是否闭合、逗号是否缺失）。`
});
console.error(`【中断】解析第 ${index + 1} 条指令时出错:`, e);
}
    });

    console.log("【步骤1.3: 解析完成】所有指令解析完毕，返回 delta 对象。");
    return { delta, smallSummary, largeSummary };
}
