        if (button.classList.contains('apply-global-preset-btn')) {
            const presetToApply = currentData.presets.find(p => p.id === id);
            if (presetToApply && await showCustomConfirm(`确定要应用预设 "${presetToApply.name}" 吗？这将覆盖你当前的面板设置。`)) {
