function getLogsForContext(allLogs, archive) {
    const openingLog = allLogs.find(log => log.content.includes('<h4>天道初启</h4>'));

    const finalLogsForPrompt = [];

    if (openingLog && !openingLog.isGhost) {
        const cleanOpening = openingLog.content.replace(/<[^>]+>/g, '').trim();
        finalLogsForPrompt.push({ 
            type: 'system', 
            content: `[世界背景设定]:\n${cleanOpening}` 
        });
    }

    const validLogs = allLogs.filter(log => 
        !log.isSnapshot && 
        !log.isUndoSnapshot && 
        (!openingLog || log.id !== openingLog.id)
    ).sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

    validLogs.forEach((log, index) => {
        if (log.isDeepSummary === true) {
            const summaryText = `[历史记忆档案 (Time: ${new Date(log.timestamp).toLocaleString()})]:\n<overview>${log.largeSummary}</overview>\n<details>${log.smallSummary}</details>`;

            finalLogsForPrompt.push({
                type: 'system',
                content: summaryText
            });
        } 
        else if (summaryConfig.segmentedMemoryEnabled && (log.smallSummary || log.largeSummary)) {
            const chatLayers = parseInt(summaryConfig.segmentedChatLayers, 10) || 20;
            const largeSummaryStart = parseInt(summaryConfig.segmentedLargeSummaryStart, 10) || 50;

            const reverseIndex = validLogs.length - 1 - index;

            if (reverseIndex >= chatLayers) {
                const contentToUse = (reverseIndex >= largeSummaryStart && log.largeSummary) 
                    ? log.largeSummary 
                    : (log.smallSummary || log.largeSummary);

                if (contentToUse) {
                    finalLogsForPrompt.push({
                        type: 'system',
                        content: `[过往记忆]: ${contentToUse}`
                    });
                } else {
                    let clean = log.content;
                    if (log.type === 'ai') {
                        clean = clean.replace(/<image>[\s\S]*?<\/image>/g, '')
                                     .replace(/image###[\s\S]*?###/g, '')
                                     .replace(/<thinking>[\s\S]*?<\/thinking>/g, '');
                    }
                    clean = clean.replace(/<[^>]+>/g, '').trim();
                    finalLogsForPrompt.push({ type: log.type, content: clean });
                }
            } else {
                let clean = log.content;
                if (log.type === 'ai') {
                    clean = clean.replace(/<image>[\s\S]*?<\/image>/g, '')
                                 .replace(/image###[\s\S]*?###/g, '')
                                 .replace(/<thinking>[\s\S]*?<\/thinking>/g, '');
                }
                clean = clean.replace(/<[^>]+>/g, '').trim();
                finalLogsForPrompt.push({ type: log.type, content: clean });
            }
        } 
        else {
            let cleanContent = log.content;
            if (log.type === 'ai') {
                cleanContent = log.content
                    .replace(/<thinking>[\s\S]*?<\/thinking>/g, '') 
                    .replace(/<image>[\s\S]*?<\/image>/g, '')
                    .replace(/image###[\s\S]*?###/g, '')
                    .replace(/<[^>]+>/g, '') 
                    .trim();
            } else if (log.type === 'user') {
                cleanContent = log.content.replace(/^> /, '').trim();
            }

            if (cleanContent) {
                finalLogsForPrompt.push({
                    type: log.type || 'system',
                    content: cleanContent
                });
            }
        }
    });

    return {
        openingLog,
        summaryLogs: [], 
        hiddenChatLogs: [],
        visibleChatLogs: validLogs.filter(l => !l.isDeepSummary), 
        logsForPrompt: finalLogsForPrompt 
    };
}


function calculateTotalBonuses() {
    const flatBonuses = {};
    const percentBonuses = {};
    const totalBonuses = {};
    const bonusBreakdown = {};
    const attributeKeys = Object.keys(CREATION_CONFIG.ATTRIBUTES);

    attributeKeys.forEach(key => {
        flatBonuses[key] = 0;
        percentBonuses[key] = 0;
        totalBonuses[key] = 0;
        bonusBreakdown[key] = [];
    });

    const equipment = [
        ...(currentPlayerData.weapon || []),
        ...(currentPlayerData.armor || []),
        ...(currentPlayerData.technique || []),
        ...(currentPlayerData.treasure || []),
    ];

    equipment.forEach(item => {
        if (!item) return;
        const effectString = (item.type === '功法') ? (item.currentEffect || '') : (item.effect || '');
        if (!effectString) return;

        const parts = effectString.split(/[,，]/);
        parts.forEach(part => {
            const match = part.trim().match(/([\u4e00-\u9fa5]+)\s*([+-])\s*(\d+\.?\d*)(\%?)/);
            if (match) {
                const attr = match[1].trim();
                const sign = match[2];
                const value = parseFloat(match[3]);
                const isPercent = match[4] === '%';

                if (attributeKeys.includes(attr)) {
                    const finalValue = (sign === '+') ? value : -value;
                    if (isPercent) {
                        percentBonuses[attr] += finalValue / 100;
                        bonusBreakdown[attr].push(`装备: +${finalValue.toFixed(1)}%`);
                    } else {
                        flatBonuses[attr] += finalValue;
                        bonusBreakdown[attr].push(`装备: ${finalValue > 0 ? '+' : ''}${finalValue}`);
                    }
                }
            }
        });
    });

    if (currentState.sectData && currentState.sectData.level > 0) {
        const sectLevel = currentState.sectData.level;
        const sectBonusPercent = sectLevel * 1; 
        attributeKeys.forEach(key => {
            percentBonuses[key] += sectBonusPercent / 100;
        });
        bonusBreakdown.globalSectBonus = `宗门等级 (Lv.${sectLevel}): 全属性 +${sectBonusPercent}%`;
    }

    if (currentState.sectData && currentState.sectData.territory) {
        Object.values(currentState.sectData.territory).forEach(building => {
            if (building && building.level > 0 && typeof building.effect === 'string') {
                const effectMatch = building.effect.match(/([\u4e00-\u9fa5]+)\s*([+-])\s*(\d+\.?\d*)%/);
                if (effectMatch) {
                    const attr = effectMatch[1].trim();
                    const valuePerLevel = parseFloat(effectMatch[3]);
                    const totalBuildingBonus = valuePerLevel * building.level;
                    if (attributeKeys.includes(attr) && !isNaN(totalBuildingBonus)) {
                        percentBonuses[attr] += totalBuildingBonus / 100;
                        bonusBreakdown[attr].push(`${building.name} (Lv.${building.level}): +${totalBuildingBonus.toFixed(1)}%`);
                    }
                }
            }
        });
    }


    const baseAttributes = currentPlayerData.detailedAttributes || {};
    attributeKeys.forEach(key => {
        const baseStat = baseAttributes[key] ? (baseAttributes[key].max || 0) : 0;
        const percentageBonus = baseStat * percentBonuses[key];
        totalBonuses[key] = Math.round(percentageBonus) + flatBonuses[key];
    });

    return { totalBonuses, bonusBreakdown };
}

    async function getCharacterStageInfo() {
