async function manualSectEvolution(storyTextForReroll = null, systemNotifications = '') {
    const { apiUrl, apiKey, apiModel, sectEvolutionRules } = worldEvolutionConfig;

    if (!apiUrl || !apiKey || !apiModel) {
        showCustomAlert('请先在世界演化设置中配置完整的API信息。');
        return;
    }
    if (!sectEvolutionRules || sectEvolutionRules.length === 0) {
        if (!storyTextForReroll) showCustomAlert('未配置任何宗门演化规则。');
        return;
    }

    const isManualTrigger = !storyTextForReroll;
    if (isManualTrigger) {
        if (!await showCustomConfirm('这将消耗API资源来手动推演宗门的发展，确定要继续吗？')) {
            return;
        }
    }

    const btn = document.getElementById('manual-sect-evolution-trigger-btn');
    let originalHtml;
    if (btn && isManualTrigger) {
        originalHtml = btn.innerHTML;
        btn.disabled = true;
        btn.innerHTML = `<i class="fas fa-spinner fa-spin"></i> 演化中...`;
    }

    const sectEvoController = new AbortController();
    const statusText = isManualTrigger ? '正在手动推演宗门发展...' : '后台宗门演化中...';
    let statusDanmaku = showDanmaku(statusText, 'status', sectEvoController, true);

    try {
        const archive = await db.archives.get(currentArchiveName);
        if (!archive) throw new Error("无法加载当前存档");

        const lastLogWithSnapshot = [...archive.data.logs].reverse().find(log => log.stateSnapshot);
        const allBios = lastLogWithSnapshot?.biographySnapshot || [];

        const sectMemberIds = new Set(currentState.sectData?.disciples?.map(d => d.id) || []);

        const sectMemberBiographies = allBios
            .filter(bio => bio.type === '人物' && sectMemberIds.has(bio.key))
            .map(bio => {
                let charName = '未知成员';
                try {
                    const charData = JSON.parse(bio.content);
                    charName = charData['1']?.split('|')[0] || bio.title;
                } catch(e){}
                return `### 成员档案: ${charName}\n${bio.content}`;
            })
            .join('\n\n---\n\n');

        let realPlayerName = "玩家";
        if (currentState['0'] && currentState['0']['B1']) {
            const pName = currentState['0']['B1']['1'];
            if (pName) realPlayerName = pName.split('|')[0];
        }

        const sectDataString = formatSectDataForAI(currentState.sectData);
        const storyText = storyTextForReroll ?? (lastAiStoryText || '近期无玩家视角的故事原文可供参考。');
        const playerSnapshot = getSingleCharacterSnapshot('B1', currentState) || '玩家数据缺失';
        const timeRowData = Array.isArray(currentState['4']) ? currentState['4'].find(row => row.id === TIME_LOCATION_ROW_ID) : (currentState['4'] ? currentState['4'][0] : null);
        const gameTime = timeRowData ? (timeRowData['0'] || '').split('/')[0].trim() : "时间未知";
        const worldGeography = generateGeographyString();
        const worldEventsLogs = (archive.data.logs || []).filter(log => log.content.startsWith('[世界大事]')).slice(-5).map(log => log.content).join('\n');
        const latestDailyPaper = lastDailyPaperContent ? extractMainContent(lastDailyPaperContent) : '暂无';
        const onScreenNpcListString = Object.values(currentState['0'] || {}).filter(c => c['0'] !== 'B1').map(c => c['1']?.split('|')[0] || c['0']).join(', ') || '无';

        let worldFactorsContext = '无世界因子';
        const firstLog = archive.data.logs?.[0];
        if (firstLog && firstLog.content && firstLog.content.includes('世界规则变动')) {
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = firstLog.content;
            const factorList = tempDiv.querySelector('details[open] > ul, details > ul');
            if (factorList) {
                const listItems = factorList.querySelectorAll('li');
                if (listItems.length > 0) {
                    worldFactorsContext = Array.from(listItems).map(li => li.textContent.replace(/\s+/g, ' ').trim()).join('\n');
                }
            }
        }

        const messages = [];
        const activeRules = sectEvolutionRules.filter(r => r.enabled !== false);

        activeRules.forEach(rule => {
            const content = rule.content
                .replace(/\$\{sectData\}/g, sectDataString)
                .replace(/\$\{storyText\}/g, storyText)
                .replace(/\$\{sectMemberBiographies\}/g, sectMemberBiographies || '宗门内暂无成员的详细传记信息。')
                .replace(/\$\{playerSnapshot\}/g, playerSnapshot)
                .replace(/\$\{onScreenNpcList\}/g, onScreenNpcListString)
                .replace(/\$\{latestDailyPaper\}/g, latestDailyPaper)
                .replace(/\$\{worldEvents\}/g, worldEventsLogs || '近期无大事发生')
                .replace(/\$\{currentTime\}/g, gameTime)
                .replace(/\$\{worldGeography\}/g, worldGeography)
                .replace(/\$\{world_factors\}/g, worldFactorsContext)
                .replace(/\$\{system_notifications\}/g, systemNotifications || '无系统通知')
                .replace(/\[玩家名\]/g, realPlayerName)
                .replace(/"name": "玩家名"/g, `"${realPlayerName}"`)
                .replace(/\$\{playerName\}/g, realPlayerName);

            const lastMessage = messages.length > 0 ? messages[messages.length - 1] : null;
            const currentRole = rule.role || 'system';

            if (lastMessage && messages[messages.length - 1].role === currentRole) {
                messages[messages.length - 1].content += '\n' + content;
            } else {
                messages.push({ role: currentRole, content: content });
            }
        });

        if (messages.length === 0) {
            throw new Error("没有规则被触发，无法进行宗门演化。");
        }

        // 【流式修改】获取显示容器并清空旧内容
        const sectStreamTarget = document.getElementById('sect-process-content');
        if (sectStreamTarget) {
            sectStreamTarget.textContent = '正在连接天道进行宗门推演...'; // 清空并显示初始状态

            // 自动切换到“宗门演化”Tab，让用户能立刻看到流式效果
            const thinkingPopup = document.getElementById('thinking-log-popup');
            if (thinkingPopup && !thinkingPopup.classList.contains('hidden')) {
                 const sectTab = thinkingPopup.querySelector('[data-tab="sect-process"]');
                 if(sectTab) sectTab.click();
            }
        }

        // 调用流式 API，传入 target 元素
        const response = await genericApiCallStream(
            apiUrl, 
            apiKey, 
            apiModel, 
            messages, 
            sectEvoController.signal, 
            false, 
            sectStreamTarget // 传入DOM元素，实现打字机效果
        );

        latestSectEvolutionResponse = response;

        if (sectEvoController.signal.aborted) return null;

        let sectDataToUpdate = null;
        const jsonMatch = response.match(/```json\s*([\s\S]*?)\s*```/s) || response.match(/(\{[\s\S]*\})/);

        if (jsonMatch && jsonMatch[1]) {
            try {
                sectDataToUpdate = JSON.parse(jsonMatch[1]);
            } catch (e) {
                console.error("宗门演化返回的JSON格式错误:", e, jsonMatch[1]);
                showErrorReport([{ title: "JSON格式错误", details: `AI返回的宗门数据无法被解析为有效的JSON。错误: ${e.message}` }], response);
                return null;
            }
        }

        if (isManualTrigger) {
            currentState.sectData = deepMerge(currentState.sectData || {}, sectDataToUpdate);
            await saveCurrentState();
            updateSectHeaderStats();

            const activeTabEl = document.querySelector('.sect-tab.active');
            if (activeTabEl) {
                activeTabEl.click();
            } else {
                openSectSystem();
            }
            showToast('宗门演化完成！', 'success');
        }

        return sectDataToUpdate; 

    } catch (error) {
        if (error.name !== 'AbortError') {
            console.error("手动宗门演化失败:", error);
            if (isManualTrigger) showCustomAlert(`宗门演化失败: ${error.message}`);
        }
        return null; 
    } finally {
        if (statusDanmaku) statusDanmaku.remove();
        if (btn && isManualTrigger) {
            btn.disabled = false;
            btn.innerHTML = originalHtml;
        }
    }
}

