        let data = await dbGet(SECT_EVOLUTION_PRESETS_KEY);
        if (!data || !data.presets || !Array.isArray(data.presets) || data.presets.length === 0) {
            const defaultRule = {
                id: 'default-sect-evolution-rule',
                name: '默认宗门演化规则',
                enabled: true,
                role: 'user',
