                activePresetId: 'default-sect-evolution',
                presets: [{ id: 'default-sect-evolution', name: '默认宗门演化配置', rules: [defaultRule] }]
            };
            await dbSet(SECT_EVOLUTION_PRESETS_KEY, data);
        }
        return data;
