function renderSectEvolutionRules() {
    const listEl = document.getElementById('sect-evolution-rules-list');
    if (!listEl) return;

    listEl.innerHTML = '';
    const rules = worldEvolutionConfig.sectEvolutionRules || [];

    if (rules.length === 0) {
        listEl.innerHTML = '<p style="text-align:center; opacity:0.7;">暂无规则，请添加或恢复默认。</p>';
        return;
    }

    let draggedItem = null;
    let dragStartIndex = -1;

    rules.forEach((rule, index) => {
        const item = document.createElement('div');
        item.className = 'regex-rule-item';
        item.draggable = true;
        item.dataset.index = index;
        item.style.opacity = rule.enabled === false ? '0.5' : '1';
        const iconColor = rule.triggerMode === 'blue' ? '#4fc3f7' : '#66bb6a';
        const roleLabel = `[${(rule.role || 'system').toUpperCase()}]`;

        item.innerHTML = `
            <div class="thinking-wb-toggle-container">
                <label class="switch">
                    <input type="checkbox" class="sect-evolution-rule-toggle" data-id="${rule.id}" ${rule.enabled !== false ? 'checked' : ''}>
                    <span class="slider round"></span>
                </label>
            </div>
            <i class="fas fa-lightbulb" style="color: ${iconColor}; margin-right: 8px;" title="触发模式: ${rule.triggerMode === 'blue' ? '时刻' : '关键词'}"></i>
            <span class="rule-name" title="${rule.name}"><span style="color: #aaa;">${roleLabel}</span> ${rule.name}</span>
            <div class="rule-actions">
                <!-- 新增上移按钮 -->
                <button class="sect-evolution-rule-move-up-btn" data-index="${index}" title="上移" ${index === 0 ? 'disabled' : ''} style="border: 1px solid #8c7853; color:#ffd700; width:28px; height:28px; border-radius:50%; background:none; cursor:pointer; margin-right:5px;"><i class="fas fa-arrow-up"></i></button>
                <!-- 新增下移按钮 -->
                <button class="sect-evolution-rule-move-down-btn" data-index="${index}" title="下移" ${index === rules.length - 1 ? 'disabled' : ''} style="border: 1px solid #8c7853; color:#ffd700; width:28px; height:28px; border-radius:50%; background:none; cursor:pointer; margin-right:5px;"><i class="fas fa-arrow-down"></i></button>

                <button class="sect-evolution-rule-edit-btn" data-id="${rule.id}"><i class="fas fa-edit"></i></button>
                <button class="sect-evolution-rule-delete-btn" data-id="${rule.id}"><i class="fas fa-trash"></i></button>
            </div>        `;

        item.addEventListener('dragstart', (e) => {
            draggedItem = e.currentTarget;
            dragStartIndex = parseInt(draggedItem.dataset.index);
            e.currentTarget.style.opacity = '0.4';
            if (e.dataTransfer) {
                e.dataTransfer.effectAllowed = 'move';
                e.dataTransfer.setData('text/plain', dragStartIndex.toString());
            }
        });

        item.addEventListener('dragend', (e) => {
            e.currentTarget.style.opacity = rule.enabled !== false ? '1' : '0.5';
            listEl.querySelectorAll('.regex-rule-item').forEach(i => {
                i.style.borderTop = '';
                i.style.borderBottom = '';
            });
        });

        item.addEventListener('dragover', (e) => {
            e.preventDefault();
            const dropTarget = e.currentTarget;
            if (dropTarget !== draggedItem) {
                const rect = dropTarget.getBoundingClientRect();
                const midY = rect.top + rect.height / 2;
                if (e.clientY < midY) {
                    dropTarget.style.borderTop = '2px solid var(--primary-color)';
                    dropTarget.style.borderBottom = '';
                } else {
                    dropTarget.style.borderTop = '';
                    dropTarget.style.borderBottom = '2px solid var(--primary-color)';
                }
            }
        });

        item.addEventListener('dragleave', (e) => {
            e.currentTarget.style.borderTop = '';
            e.currentTarget.style.borderBottom = '';
        });

        item.addEventListener('drop', async (e) => {
            e.preventDefault();
            const dropTarget = e.currentTarget;
            dropTarget.style.borderTop = '';
            dropTarget.style.borderBottom = '';

            if (!draggedItem || draggedItem === dropTarget) return;

            const dropTargetIndex = parseInt(dropTarget.dataset.index);
            const rect = dropTarget.getBoundingClientRect();
            const midY = rect.top + rect.height / 2;
            const insertBefore = e.clientY < midY;

            const presetsData = await dbGet(SECT_EVOLUTION_PRESETS_KEY);
            const activePreset = presetsData.presets.find(p => p.id === presetsData.activePresetId);

            const [removedItemData] = activePreset.rules.splice(dragStartIndex, 1);

            let finalInsertIndex;
            if (insertBefore) {
                finalInsertIndex = (dragStartIndex < dropTargetIndex) ? dropTargetIndex - 1 : dropTargetIndex;
            } else {
                finalInsertIndex = (dragStartIndex < dropTargetIndex) ? dropTargetIndex : dropTargetIndex + 1;
            }
            if (finalInsertIndex < 0) finalInsertIndex = 0;

            activePreset.rules.splice(finalInsertIndex, 0, removedItemData);

            await dbSet(SECT_EVOLUTION_PRESETS_KEY, presetsData);
            worldEvolutionConfig.sectEvolutionRules = activePreset.rules;
            await renderSectEvolutionRules();
        });

        listEl.appendChild(item);
    });

    if (!listEl.dataset.listener) {
        listEl.addEventListener('click', async (e) => {
            const target = e.target;
            const button = target.closest('button');
            const toggle = target.closest('.sect-evolution-rule-toggle');

            if (!button && !toggle) return;

            const presetsData = await dbGet(SECT_EVOLUTION_PRESETS_KEY);
            if (!presetsData) return;
            const activePreset = presetsData.presets.find(p => p.id === presetsData.activePresetId);
            if (!activePreset) return;

            const rulesList = activePreset.rules || [];

            if (toggle) {
                const ruleId = toggle.dataset.id;
                const rule = rulesList.find(r => r.id === ruleId);
                if (rule) rule.enabled = toggle.checked;

            } else if (button) {
                // 获取 data-index (用于移动) 或 data-id (用于编辑/删除)
                const index = parseInt(button.dataset.index);
                const ruleId = button.dataset.id;
                // 如果有ID则查找索引，否则直接使用 dataset.index
                const ruleIndex = ruleId ? rulesList.findIndex(r => r.id === ruleId) : index;

                if (button.classList.contains('sect-evolution-rule-edit-btn')) {
                    openSectEvolutionRuleEditor(ruleId);
                } else if (button.classList.contains('sect-evolution-rule-delete-btn')) {
                    if (ruleIndex > -1 && await showCustomConfirm('确定要删除此规则吗？')) {
                        rulesList.splice(ruleIndex, 1);
                    }
                } 
                // --- 新增：处理上移 ---
                else if (button.classList.contains('sect-evolution-rule-move-up-btn')) {
                    if (ruleIndex > 0) {
                        [rulesList[ruleIndex], rulesList[ruleIndex - 1]] = [rulesList[ruleIndex - 1], rulesList[ruleIndex]];
                    }
                } 
                // --- 新增：处理下移 ---
                else if (button.classList.contains('sect-evolution-rule-move-down-btn')) {
                    if (ruleIndex < rulesList.length - 1) {
                        [rulesList[ruleIndex], rulesList[ruleIndex + 1]] = [rulesList[ruleIndex + 1], rulesList[ruleIndex]];
                    }
                }
            }

            await dbSet(SECT_EVOLUTION_PRESETS_KEY, presetsData);
            worldEvolutionConfig.sectEvolutionRules = rulesList;
            renderSectEvolutionRules();
        });
        listEl.dataset.listener = 'true';
    }
}

