function drawPixelArt(canvas, pixelData, tileSize = 8) {
    if (!canvas || !pixelData || pixelData.length === 0) return;
    const ctx = canvas.getContext('2d');
    const rows = pixelData.length;
    const cols = pixelData[0].length;

    canvas.width = cols * tileSize;
    canvas.height = rows * tileSize;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
            const char = pixelData[y][x];
            if (char && char !== ' ') {
                const style = TILE_PALETTE[char];
                if (style) {
                    ctx.fillStyle = style.bg;
                    ctx.fillRect(x * tileSize, y * tileSize, tileSize, tileSize);
                }
            }
        }
    }
}

async function autoGenerateCharacterWorldBooks(updatedCharacterIds, logEntry, finalState) {
    if (!knowledgeSearchGlobalConfig.knowledgeBaseEnabled || !knowledgeSearchGlobalConfig.attachBiographyToSnapshot) {
        return;
    }
    if (!updatedCharacterIds || updatedCharacterIds.size === 0) {
        return;
    }
    const archive = await db.archives.get(currentArchiveName);
    let previousBiographies = [];
    if (archive && archive.data.logs) {
        const lastLogWithBio = [...archive.data.logs].reverse().find(log => log.biographySnapshot && log.id !== logEntry.id);
        if (lastLogWithBio) {
            previousBiographies = lastLogWithBio.biographySnapshot;
        }
    }
    let biographiesToUpdate = [...previousBiographies];
    let changesMade = false;
    for (const charId of updatedCharacterIds) {
        if (!charId.startsWith('C') && !charId.startsWith('G')) {
            continue;
        }
        const charData = finalState['0'][charId];
        if (!charData) continue;
        const characterSnapshotContent = getSingleCharacterSnapshot(charId, finalState);
        const charName = charData['1']?.split('|')[0] || charId;
        // 1. 尝试通过 ID 匹配
        let existingEntryIndex = biographiesToUpdate.findIndex(bio => bio.key === charId);
        // 2. 如果 ID 没匹配上，尝试通过 名字 匹配 (处理复活换ID但名字相同的情况)
        if (existingEntryIndex === -1) {
            existingEntryIndex = biographiesToUpdate.findIndex(bio => bio.title === charName && (bio.type === '人物' || !bio.type));
        }
        if (existingEntryIndex !== -1) {
            const entry = biographiesToUpdate[existingEntryIndex];

            const isIdChanged = entry.key !== charId;
            const isRenamed = entry.title !== charName;
            const isContentChanged = entry.content !== characterSnapshotContent;
            if (isRenamed || isContentChanged || isIdChanged) {
                entry.content = characterSnapshotContent;

                // 关键修复：如果是同名不同ID，更新 key 为新 ID
                if (isIdChanged) {
                    console.log(`[自动传记] 检测到同名角色 '${charName}' ID变更: ${entry.key} -> ${charId}，已合并档案。`);
                    entry.key = charId;
                }

                if (isRenamed) {
                    entry.title = charName;
                    entry.keywords = [charName];
                }

                changesMade = true;
            }
        } else {
            const newEntry = {
                id: crypto.randomUUID(),
                key: charId,
                title: charName,
                type: '人物',
                content: characterSnapshotContent,
                enabled: true,
                triggerMode: 'green',
                keywords: [charName],
                depth: knowledgeSearchGlobalConfig.worldBookSearchDepth || 5,
            };
            biographiesToUpdate.push(newEntry);
            changesMade = true;
        }
    }
    if (changesMade) {
        logEntry.biographySnapshot = biographiesToUpdate;
        console.log(`[世界档案-快照模式] 成功更新/创建了 ${updatedCharacterIds.size} 位人物的传记快照。`);
    } else {
        logEntry.biographySnapshot = previousBiographies;
    }
}async function generateFactionWorldBooks(storyTextForApi, apiConfigToUse, controller, latestState, factionRules, saveToDb = true) {
    const { apiUrl, apiModel, apiKey } = apiConfigToUse;

    const DEFAULT_FACTION_RULE = {
        id: 'default-faction-rule',
        name: '默认势力档案生成规则',
        enabled: true,
        role: 'system',
        triggerMode: 'blue',
        keywords: [],
        content: AUTO_FACTION_WORLDBOOK_PROMPT_TEMPLATE,
    };

    let rulesToUse = (factionRules && factionRules.length > 0)
        ? factionRules.filter(r => r.enabled !== false)
        : [DEFAULT_FACTION_RULE];

    if (rulesToUse.length === 0) {
        console.warn("势力档案生成跳过：所有可用规则均未启用。");
        return;
    }

    const textToSearch = storyTextForApi || '';
    const archive = await db.archives.get(currentArchiveName);
    let allEntries = [];
    const isSnapshotMode = knowledgeSearchGlobalConfig.attachBiographyToSnapshot;
    if (isSnapshotMode) {
        const lastLogWithBio = archive?.data?.logs.slice().reverse().find(log => log.biographySnapshot);
        if (lastLogWithBio) allEntries = lastLogWithBio.biographySnapshot;
    } else {
        allEntries = archive?.data?.state.worldBookEntries || [];
    }

    let existingEntryContent = '';
    rulesToUse.forEach(rule => {
        if (rule.triggerMode === 'green' && rule.keywords && rule.keywords.length > 0) {
            const foundKeyword = rule.keywords.find(kw => textToSearch.includes(kw));
            if (foundKeyword) {
                const existingEntry = allEntries.find(e => e.key === foundKeyword || e.title === foundKeyword);
                if (existingEntry) {
                    existingEntryContent += `\n\n### 已知 "${foundKeyword}" 的情报:\n${existingEntry.content}`;
                }
            }
        }
    });

    const timeRow = (latestState['4'] && latestState['4'][0]) ? latestState['4'][0] : null;
    const currentTime = timeRow ? (timeRow['0'] || '').split('/')[0] : '未知时间';

    const messages = [];

    rulesToUse.forEach(rule => {
        let isTriggered = false;

        if (rule.triggerMode === 'blue') {
            isTriggered = true;
        } else if (rule.triggerMode === 'green') {
            if (rule.keywords && rule.keywords.length > 0) {
                const foundKeyword = rule.keywords.find(kw => textToSearch.includes(kw));
                if (foundKeyword) {
                    isTriggered = true;
                    console.log(`[势力档案] 绿灯规则 "${rule.name}" 被关键词 "${foundKeyword}" 触发`);
                }
            }
        }

        if (isTriggered) {
            let content = rule.content
                .replace(/\$\{storyText\}/g, storyTextForApi)
                .replace(/\$\{currentTime\}/g, currentTime)
                .replace(/\$\{existingEntryContent\}/g, existingEntryContent || '无');

            let targetRole = rule.role || 'user';

            const lastMsg = messages.length > 0 ? messages[messages.length - 1] : null;
            if (lastMsg && lastMsg.role === targetRole) {
                lastMsg.content += '\n' + content;
            } else {
                messages.push({ role: targetRole, content });
            }
        }
    });

    if (messages.length === 0) {
        console.log("势力档案生成跳过：没有规则被触发。");
        return;
    }

    let aiResponse = '';
    let statusDanmaku = null;
    const maxRetries = 3;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        if (controller.signal.aborted) return;
        try {
            if(statusDanmaku) statusDanmaku.remove();
            statusDanmaku = showDanmaku(attempt > 1 ? `重试势力档案分析 (${attempt}/${maxRetries})...` : '分析势力/秘境档案...', 'status', controller, true);

            aiResponse = await genericApiCall(apiUrl, apiKey, apiModel, messages, controller.signal);

            if (controller.signal.aborted) return;

            const cleanJsonString = extractJsonArrayFromString(aiResponse);
            if (cleanJsonString) {
                aiResponse = cleanJsonString;
                break;
            }

            if (attempt === maxRetries) {
                throw new Error("AI 返回内容格式不正确，多次重试后仍然失败。");
            }
        } catch (e) {
            if (e.name === 'AbortError') return;
            console.error(`[势力档案] API请求出错 (尝试 ${attempt}):`, e);

            if (attempt === maxRetries) {
                if (statusDanmaku) statusDanmaku.remove();
                throw new Error(`API 请求连续失败 3 次: ${e.message}`);
            }
            await new Promise(resolve => setTimeout(resolve, 2000 * attempt));
        }
    }

    if (statusDanmaku) statusDanmaku.remove();

    if (!aiResponse) return;

    let newEntries = [];
    try {
        newEntries = JSON.parse(aiResponse);
    } catch (e) {
        console.error("最终解析JSON失败:", e);
        return;
    }
    if (!Array.isArray(newEntries) || newEntries.length === 0) return;

    let hasChanges = false;
    const tempMap = new Map();
    allEntries.forEach(e => tempMap.set(e.key || e.title, e));
    const updatesToMerge = new Map();

    for (const item of newEntries) {
        const itemTitle = item.title;
        if (!itemTitle || !item.type) continue;

        const keywordsArray = (Array.isArray(item.keywords) ? item.keywords : [item.title]).map(k => k.trim()).filter(Boolean);

        const existingEntry = tempMap.get(itemTitle);

        if (existingEntry) {
            const oldData = JSON.parse(existingEntry.content || '{}');
            const newDataFromAI = item;

            const mergedData = deepMerge(oldData, newDataFromAI);
            const newMergedContent = JSON.stringify(mergedData, null, 2);

            const mergedKeywords = Array.from(new Set([...(existingEntry.keywords || []), ...keywordsArray]));

            if (existingEntry.content !== newMergedContent || JSON.stringify(existingEntry.keywords) !== JSON.stringify(mergedKeywords)) {
                existingEntry.content = newMergedContent;
                existingEntry.keywords = mergedKeywords;
                updatesToMerge.set(itemTitle, existingEntry);
                hasChanges = true;
            }
        } else {
            const newEntryData = {
                id: crypto.randomUUID(),
                key: itemTitle,
                title: itemTitle,
                type: item.type,
                content: JSON.stringify(item),
                triggerMode: 'green',
                keywords: Array.from(new Set([...keywordsArray, itemTitle])),
                depth: knowledgeSearchGlobalConfig.worldBookSearchDepth || 5,
                enabled: true,
                role: 'user',
            };
            updatesToMerge.set(itemTitle, newEntryData);
            hasChanges = true;
        }
    }

    if (!saveToDb) {
        return { success: true, hasChanges: hasChanges, updatesMap: updatesToMerge };
    }

    if (hasChanges && updatesToMerge.size > 0) {
        const freshArchive = await db.archives.get(currentArchiveName);
        let targetList = [];
        let targetLogIndex = -1;

        if (isSnapshotMode) {
            targetLogIndex = freshArchive.data.logs.findLastIndex(log => log.biographySnapshot);
            if (targetLogIndex === -1) {
                targetLogIndex = freshArchive.data.logs.findLastIndex(log => log.stateSnapshot);
            }
            if (targetLogIndex !== -1) {
                targetList = freshArchive.data.logs[targetLogIndex].biographySnapshot || [];
            }
        } else {
            if (!freshArchive.data.state) freshArchive.data.state = {};
            targetList = freshArchive.data.state.worldBookEntries || [];
        }

        const masterMap = new Map();
        [...allEntries, ...targetList].forEach(e => masterMap.set(e.key || e.title, e));

        updatesToMerge.forEach((entry, key) => {
            masterMap.set(key, entry); 
        });

        const finalEntriesArray = Array.from(masterMap.values());

        if (isSnapshotMode && targetLogIndex !== -1) {
             freshArchive.data.logs[targetLogIndex].biographySnapshot = finalEntriesArray;
        } else {
            freshArchive.data.state.worldBookEntries = finalEntriesArray;
        }

        await db.archives.put(freshArchive);
        showDanmaku(`成功生成/更新了 ${updatesToMerge.size} 条势力等档案！`, 'success');
    } else {
        showDanmaku('未发现新的势力信息。', 'info');
    }
}
