function drawPixelTerrain(ctx, width, height, theme) {
    // 像素化基础大小
    const tileSize = 20; 
    const cols = Math.ceil(width / tileSize);
    const rows = Math.ceil(height / tileSize);

    // 1. 基础底色填充
    let baseColor, highlightColor, shadowColor;

    switch (theme) {
        case 'grass': // 草地风格
            baseColor = '#567d46';
            highlightColor = '#6a9256';
            shadowColor = '#436337';
            break;
        case 'wood': // 木地板风格
            baseColor = '#7f5f38';
            highlightColor = '#916f45';
            shadowColor = '#5e4528';
            break;
        case 'stone': // 石砖风格
            baseColor = '#3b3b3b';
            highlightColor = '#4f4f4f';
            shadowColor = '#292929';
            break;
        case 'dirt': // 土地风格
            baseColor = '#5d4037';
            highlightColor = '#6d4c41';
            shadowColor = '#4e342e';
            break;
        default: // 默认深色
            baseColor = '#2e3033';
            highlightColor = 'rgba(255, 255, 255, 0.03)';
            shadowColor = 'rgba(0, 0, 0, 0.1)';
            break;
    }

    ctx.fillStyle = baseColor;
    ctx.fillRect(0, 0, width, height);

    // 2. 绘制像素纹理
    for (let i = 0; i < cols; i++) {
        for (let j = 0; j < rows; j++) {
            const x = i * tileSize;
            const y = j * tileSize;
            const rand = Math.random();

            if (theme === 'grass') {
                // 草地：随机画一些小草丛
                if (rand > 0.7) {
                    ctx.fillStyle = shadowColor;
                    ctx.fillRect(x + 5, y + 5, 4, 8);
                    ctx.fillStyle = highlightColor;
                    ctx.fillRect(x + 4, y + 4, 4, 6);
                }
            } else if (theme === 'wood') {
                // 木地板：画横条纹
                ctx.fillStyle = shadowColor;
                ctx.fillRect(x, y + tileSize - 2, tileSize, 2); // 板缝
                if (rand > 0.8) { // 木结
                    ctx.fillStyle = shadowColor;
                    ctx.fillRect(x + 5, y + 5, 4, 2);
                }
            } else if (theme === 'stone') {
                // 石砖：画网格
                ctx.strokeStyle = shadowColor;
                ctx.lineWidth = 2;
                ctx.strokeRect(x, y, tileSize, tileSize);
                if (rand > 0.8) { // 裂纹
                    ctx.fillStyle = highlightColor;
                    ctx.fillRect(x + 2, y + 2, tileSize - 4, tileSize - 4);
                }
            } else if (theme === 'dirt') {
                // 土地：随机噪点
                if (rand > 0.5) {
                    ctx.fillStyle = rand > 0.75 ? highlightColor : shadowColor;
                    ctx.fillRect(x + Math.random() * 10, y + Math.random() * 10, 4, 4);
                }
            } else {
                // 默认噪点
                 if (rand > 0.9) { 
                    ctx.fillStyle = highlightColor;
                    ctx.fillRect(x + 5, y + 5, 4, 4);
                }
            }
        }
    }

    // 3. 添加复古暗角效果
    const gradient = ctx.createRadialGradient(width/2, height/2, Math.min(width, height)/3, width/2, height/2, Math.max(width, height));
    gradient.addColorStop(0, 'rgba(0,0,0,0)');
    gradient.addColorStop(1, 'rgba(0,0,0,0.4)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, width, height);
}

const WALKABLE_TILES = new Set(['"', '.', ',', 's', '_', '=', 'c', 'y', 'r', 'b', 'U', 't', 'u', '*', '^', '~', 'l', 'i', 'd', 'm', 'F', 'W', 'C', 'J', 'K', 'P', 'A', 'O', 'w', 'v', 'k', 'E', 'z', 'Z', 'Y', 'a', 'h', 'p', 'j', '#', '+', 'D', '%', '>', '<', 'H', '|', '$', 'T', 'B', 'L', 'G', 'f', 'X', '@', 'x', '!', 'M', 'o']);

const TILE_PALETTE = {
