// 2. 程序化纹理绘制器 (核心黑科技)
function drawProceduralTile(ctx, char, x, y, w, h) {
    const style = TILE_PALETTE[char] || TILE_PALETTE['.'];
    ctx.fillStyle = style.bg;
    ctx.fillRect(x, y, w, h);
    ctx.fillStyle = style.fg;
    const rand = (x + y * 57) % 100 / 100;
    switch (style.type) {
        case 'grass': if (rand > 0.6) { ctx.fillRect(x + w * 0.2, y + h * 0.5, w * 0.1, h * 0.3); ctx.fillRect(x + w * 0.4, y + h * 0.4, w * 0.1, h * 0.4); ctx.fillRect(x + w * 0.6, y + h * 0.6, w * 0.1, h * 0.2); } break;
        case 'dirt': if (rand > 0.5) { ctx.fillStyle = '#c7b595'; ctx.fillRect(x + w * 0.2, y + h * 0.3, 3, 3); } if (rand < 0.2) { ctx.fillStyle = '#c7b595'; ctx.fillRect(x + w * 0.8, y + h * 0.7, 3, 3); } break;
        case 'tree': ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.4, 0, Math.PI * 2); ctx.fill(); break;
        case 'mountain': ctx.beginPath(); ctx.moveTo(x + w * 0.2, y + h); ctx.lineTo(x + w * 0.5, y + h * 0.2); ctx.lineTo(x + w * 0.8, y + h); ctx.fill(); break;
        case 'water_deep': case 'water_shallow': ctx.fillRect(x + w * 0.1, y + h * 0.3, w * 0.5, h * 0.1); ctx.fillRect(x + w * 0.4, y + h * 0.6, w * 0.5, h * 0.1); break;
        case 'lava': if (rand > 0.5) { ctx.fillStyle = '#ffccbc'; ctx.fillRect(x + w * 0.3, y + h * 0.3, w * 0.4, h * 0.4); } break;
        case 'sand': if (rand > 0.3) ctx.fillRect(x + w * 0.2, y + h * 0.2, 2, 2); if (rand > 0.6) ctx.fillRect(x + w * 0.7, y + h * 0.7, 2, 2); break;
        case 'ice': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(x + w * 0.2, y + h); ctx.lineTo(x + w, y + h * 0.2); ctx.stroke(); break;
        case 'wall_stone': ctx.fillRect(x, y + h * 0.45, w, h * 0.1); ctx.fillRect(x + w * 0.45, y, w * 0.1, h * 0.45); ctx.fillRect(x + w * 0.2, y + h * 0.55, w * 0.1, h * 0.45); break;
        case 'wall_wood': ctx.fillRect(x + w * 0.2, y, w * 0.1, h); ctx.fillRect(x + w * 0.5, y, w * 0.1, h); ctx.fillRect(x + w * 0.8, y, w * 0.1, h); break;
        case 'floor_wood': ctx.fillRect(x, y + h * 0.9, w, h * 0.1); if (rand > 0.8) ctx.fillRect(x + w * 0.1, y + h * 0.4, w * 0.1, h * 0.1); break;
        case 'road_stone': ctx.strokeStyle = style.fg; ctx.strokeRect(x + 2, y + 2, w - 4, h - 4); break;
        case 'carpet': ctx.fillStyle = '#e57373'; ctx.fillRect(x + w * 0.2, y + h * 0.2, w * 0.6, h * 0.6); break;
        case 'swamp': ctx.fillStyle = '#6b8e23'; if (rand > 0.3) ctx.fillRect(x + w * 0.1, y + h * 0.7, w * 0.3, h * 0.2); if (rand > 0.6) ctx.fillRect(x + w * 0.6, y + h * 0.8, w * 0.3, h * 0.1); ctx.strokeStyle = style.fg; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(x, y + h * 0.3); ctx.bezierCurveTo(x + w * 0.3, y + h * 0.2, x + w * 0.7, y + h * 0.4, x + w, y + h * 0.3); ctx.stroke(); break;
        case 'flowers': ctx.fillStyle = TILE_PALETTE['"'].bg; ctx.fillRect(x, y, w, h); if (rand > 0.2) { ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.3, y + h * 0.3, w * 0.2, w * 0.2); } if (rand > 0.5) { ctx.fillStyle = '#fff176'; ctx.fillRect(x + w * 0.6, y + h * 0.6, w * 0.2, w * 0.2); } break;
        case 'snow': if (rand > 0.8) { ctx.fillStyle = '#e0f7fa'; ctx.fillRect(x, y, w, h * 0.1); } break;
        case 'door': ctx.fillStyle = style.fg; ctx.fillRect(x, y, w, h * 0.1); ctx.fillRect(x, y + h * 0.9, w, h * 0.1); ctx.fillRect(x, y, w * 0.1, h); ctx.fillRect(x + w * 0.9, y, w * 0.1, h); if (rand > 0.5) { ctx.fillStyle = '#ffd700'; ctx.fillRect(x + w * 0.7, y + h * 0.45, w * 0.1, w * 0.1); } break;
        case 'window': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.4, y + h * 0.1, w * 0.2, h * 0.8); ctx.fillRect(x + w * 0.1, y + h * 0.4, w * 0.8, h * 0.2); break;
        case 'stairs_down': ctx.strokeStyle = style.fg; ctx.lineWidth = w * 0.2; for (let i = 0; i < 3; i++) { ctx.beginPath(); ctx.moveTo(x + w * (i * 0.3), y); ctx.lineTo(x + w * (i * 0.3 + 0.5), y + h); ctx.stroke(); } break;
        case 'stairs_up': ctx.strokeStyle = style.fg; ctx.lineWidth = w * 0.2; for (let i = 0; i < 3; i++) { ctx.beginPath(); ctx.moveTo(x + w * (i * 0.3 + 0.5), y); ctx.lineTo(x + w * (i * 0.3), y + h); ctx.stroke(); } break;
        case 'bridge': ctx.fillStyle = style.fg; ctx.fillRect(x, y + h * 0.1, w, h * 0.2); ctx.fillRect(x, y + h * 0.7, w, h * 0.2); break;
        case 'chest': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.2, y + h * 0.2, w * 0.6, h * 0.6); ctx.fillStyle = '#a1887f'; ctx.fillRect(x + w * 0.4, y + h * 0.1, w * 0.2, h * 0.3); break;
        case 'web': ctx.strokeStyle = style.fg; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(x + w * 0.5, y + h * 0.5); ctx.lineTo(x, y); ctx.moveTo(x + w * 0.5, y + h * 0.5); ctx.lineTo(x + w, y); ctx.moveTo(x + w * 0.5, y + h * 0.5); ctx.lineTo(x, y + h); ctx.moveTo(x + w * 0.5, y + h * 0.5); ctx.lineTo(x + w, y + h); ctx.stroke(); ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.3, 0, Math.PI * 2); ctx.stroke(); break;
        case 'cracked_land': ctx.strokeStyle = style.fg; ctx.lineWidth = 1.5; ctx.beginPath(); ctx.moveTo(x + w * 0.1, y + h * 0.1); ctx.lineTo(x + w * 0.4, y + h * 0.4); ctx.lineTo(x + w * 0.3, y + h * 0.7); ctx.lineTo(x + w * 0.6, y + h); ctx.moveTo(x + w * 0.4, y + h * 0.4); ctx.lineTo(x + w, y + h * 0.2); ctx.stroke(); break;
        case 'jungle': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.1, y, w * 0.2, h); ctx.fillRect(x + w * 0.7, y, w * 0.2, h); ctx.strokeStyle = '#2e7d32'; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(x, y); ctx.bezierCurveTo(x + w * 0.5, y + h * 0.5, x + w * 0.2, y + h * 0.8, x + w, y + h); ctx.stroke(); break;
        case 'crystal': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.moveTo(x + w * 0.5, y + h * 0.1); ctx.lineTo(x + w * 0.2, y + h * 0.5); ctx.lineTo(x + w * 0.5, y + h * 0.9); ctx.lineTo(x + w * 0.8, y + h * 0.5); ctx.fill(); break;
        case 'poison_swamp': ctx.fillStyle = style.fg; if (rand > 0.4) ctx.fillRect(x + w * 0.2, y + h * 0.2, w * 0.2, w * 0.2); if (rand > 0.6) ctx.fillRect(x + w * 0.7, y + h * 0.7, w * 0.15, w * 0.15); break;
        case 'ash_land': ctx.fillStyle = style.fg; if (rand > 0.3) ctx.fillRect(x + w * 0.1, y + h * 0.1, 2, 2); if (rand > 0.5) ctx.fillRect(x + w * 0.5, y + h * 0.6, 3, 3); if (rand > 0.7) ctx.fillRect(x + w * 0.8, y + h * 0.2, 2, 2); break;
        case 'spring': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.3, 0, Math.PI * 2); ctx.fill(); break;
        case 'cave_floor': ctx.fillStyle = style.fg; if (rand > 0.6) { ctx.beginPath(); ctx.moveTo(x + w * 0.4, y + h); ctx.lineTo(x + w * 0.5, y + h * 0.6); ctx.lineTo(x + w * 0.6, y + h); ctx.fill(); } break;
        case 'pillar': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.3, y, w * 0.4, h); ctx.fillStyle = TILE_PALETTE['#'].bg; ctx.fillRect(x + w * 0.4, y, w * 0.2, h); break;
        case 'altar': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.1, y + h * 0.5, w * 0.8, h * 0.3); ctx.fillStyle = '#614124'; ctx.fillRect(x + w * 0.3, y + h * 0.3, w * 0.4, h * 0.2); break;
        case 'throne': ctx.fillRect(x + w * 0.2, y + h * 0.5, w * 0.6, h * 0.4); ctx.fillRect(x + w * 0.1, y + h * 0.2, w * 0.8, h * 0.3); break;
        case 'bed': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.1, y + h * 0.1, w * 0.3, h * 0.4); ctx.fillStyle = '#9e9e9e'; ctx.fillRect(x + w * 0.1, y + h * 0.5, w * 0.8, h * 0.4); break;
        case 'table': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.1, y + h * 0.3, w * 0.8, h * 0.4); break;
        case 'bookshelf': ctx.fillStyle = style.fg; ctx.fillRect(x, y + h * 0.2, w, h * 0.1); ctx.fillRect(x, y + h * 0.5, w, h * 0.1); ctx.fillRect(x, y + h * 0.8, w, h * 0.1); break;
        case 'grate': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.4, y, w * 0.2, h); ctx.fillRect(x + w * 0.7, y, w * 0.2, h); ctx.fillRect(x, y + h * 0.4, w, h * 0.2); break;
        case 'torch': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.2, 0, Math.PI * 2); ctx.fill(); break;
        case 'pitfall': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x + w, y + h); ctx.moveTo(x + w, y); ctx.lineTo(x, y + h); ctx.stroke(); break;
        case 'trap': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.moveTo(x + w * 0.5, y + h * 0.2); ctx.lineTo(x + w * 0.2, y + h * 0.8); ctx.lineTo(x + w * 0.8, y + h * 0.8); ctx.fill(); break;
        case 'portal': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; for (let i = 1; i <= 3; i++) { ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, (w * 0.1) * i, rand * Math.PI * 2, (rand + 0.5) * Math.PI * 2); ctx.stroke(); } break;
        case 'switch': ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.2, 0, Math.PI * 2); ctx.fill(); break;
        case 'rubble': if (rand > 0.2) ctx.fillRect(x + w * 0.1, y + h * 0.6, w * 0.4, h * 0.3); if (rand > 0.5) ctx.fillRect(x + w * 0.6, y + h * 0.2, w * 0.3, h * 0.4); break;
        case 'bones': ctx.fillRect(x + w * 0.3, y + h * 0.2, w * 0.4, h * 0.3); ctx.fillRect(x + w * 0.1, y + h * 0.6, w * 0.8, h * 0.2); break;
        case 'waterfall': ctx.fillStyle = style.fg; ctx.fillRect(x, y, w, h * 0.2); ctx.fillRect(x, y + h * 0.4, w, h * 0.2); ctx.fillRect(x, y + h * 0.8, w, h * 0.2); break;
        case 'spirit_vein': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(x, y + h * 0.5); ctx.bezierCurveTo(x + w * 0.3, y + h * 0.2, x + w * 0.7, y + h * 0.8, x + w, y + h * 0.5); ctx.stroke(); break;
        case 'herb_garden': if (rand > 0.3) { ctx.fillStyle = '#f48fb1'; ctx.fillRect(x + w * 0.2, y + h * 0.2, 4, 4); } if (rand > 0.6) { ctx.fillStyle = '#9575cd'; ctx.fillRect(x + w * 0.7, y + h * 0.6, 4, 4); } break;
        case 'mineral_vein': if (rand > 0.3) { ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.3, y + h * 0.6, w * 0.4, h * 0.1); } break;
        case 'battlefield': ctx.fillStyle = style.fg; if (rand > 0.2) ctx.fillRect(x + w * 0.1, y + h * 0.8, w * 0.3, h * 0.1); if (rand > 0.7) ctx.fillRect(x + w * 0.6, y + h * 0.1, w * 0.1, h * 0.4); break;
        case 'seal': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(x + w / 2, y + h / 2, w * 0.4, 0, Math.PI * 2); ctx.moveTo(x + w / 2, y + h * 0.1); ctx.lineTo(x + w / 2, y + h * 0.9); ctx.moveTo(x + w * 0.1, y + h / 2); ctx.lineTo(x + w * 0.9, y + h / 2); ctx.stroke(); break;
        case 'sect_hall': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.moveTo(x, y + h * 0.5); ctx.lineTo(x + w * 0.5, y + h * 0.1); ctx.lineTo(x + w, y + h * 0.5); ctx.fill(); ctx.fillRect(x + w * 0.1, y + h * 0.5, w * 0.8, h * 0.4); break;
        case 'training_ground': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(x + w/2, y + h/2, w * 0.4, 0, Math.PI * 2); ctx.stroke(); break;
        case 'alchemy_room': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.arc(x + w * 0.5, y + h * 0.5, w * 0.2, 0, Math.PI * 2); ctx.fill(); break;
        case 'refining_room': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.3, y + h * 0.3, w * 0.4, h * 0.4); break;
        case 'pagoda': ctx.fillStyle = style.fg; ctx.fillRect(x + w * 0.1, y + h * 0.8, w * 0.8, h * 0.1); ctx.fillRect(x + w * 0.2, y + h * 0.5, w * 0.6, h * 0.1); ctx.fillRect(x + w * 0.3, y + h * 0.2, w * 0.4, h * 0.1); break;
        case 'cushion': ctx.fillStyle = style.fg; ctx.beginPath(); ctx.ellipse(x + w / 2, y + h * 0.7, w * 0.4, h * 0.2, 0, 0, Math.PI * 2); ctx.fill(); break;
        case 'sword_grave': ctx.strokeStyle = style.fg; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(x + w * 0.3, y + h * 0.8); ctx.lineTo(x + w * 0.3, y + h * 0.3); ctx.moveTo(x + w * 0.7, y + h * 0.9); ctx.lineTo(x + w * 0.7, y + h * 0.4); ctx.stroke(); break;
    }
}

async function animatePlayerOnMap(path, playerElement, renderer) {
    if (!path || path.length < 2 || !playerElement || !renderer) return;

    const moveSpeed = 150;
    const totalDuration = (path.length - 1) * moveSpeed;
    let startTime = null;

    const canvas = renderer.canvas;
    canvas.style.pointerEvents = 'none';

    console.log(`[animatePlayerOnMap] Animation started. Path length: ${path.length}`);

    const step = (timestamp) => {
        if (!startTime) startTime = timestamp;
        const elapsed = timestamp - startTime;
        const progress = Math.min(elapsed / totalDuration, 1);

        const pathIndex = Math.floor(progress * (path.length - 1));
        const segmentProgress = (progress * (path.length - 1)) - pathIndex;

        const startPos = path[pathIndex];
        const endPos = path[pathIndex + 1] || startPos;

        const currentGridX = startPos[0] + (endPos[0] - startPos[0]) * segmentProgress;
        const currentGridY = startPos[1] + (endPos[1] - startPos[1]) * segmentProgress;

        const terrain = renderer.mapConfig.terrain || [];
        const rows = terrain.length > 0 ? terrain.length : 20;
        const cols = terrain.length > 0 ? (terrain[0] || '').length : 20;

        playerElement.coords[0] = ((currentGridX + 0.5) / cols) * 100;
        playerElement.coords[1] = ((currentGridY + 0.5) / rows) * 100;

        renderer.draw();

        if (progress < 1) {
            requestAnimationFrame(step);
        } else {
            const finalGridPos = path[path.length - 1];
            const terrainChar = renderer.mapConfig.terrain[finalGridPos[1]]?.[finalGridPos[0]] || '.';
            const terrainName = TILE_PALETTE[terrainChar]?.name || '未知区域';

            console.log(`[animatePlayerOnMap] Animation finished at [${finalGridPos[0]}, ${finalGridPos[1]}]. Terrain: ${terrainName}`);

            const timeLocationDisplay = document.getElementById('time-location-display');
            if (timeLocationDisplay) {
                const parts = timeLocationDisplay.textContent.split('/');
                const time = parts[0];
                const mainLocation = parts[1];
                if (mainLocation && terrainName) {
                    timeLocationDisplay.textContent = `${time}/${mainLocation}/${terrainName}`;
                }
            }

            canvas.style.pointerEvents = 'auto';
        }
    };

    requestAnimationFrame(step);
}


async function renderSceneMap(canvas, mapConfig, isLargeMap = false) {
    if (!canvas) return;
    mapConfig = mapConfig || {};

    const sceneData = Array.isArray(mapConfig.elements) ? mapConfig.elements : [];
    const terrainMap = Array.isArray(mapConfig.terrain) ? mapConfig.terrain : [];

    // --- 1. 准备画布 ---
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();

    if (canvas.width !== rect.width * dpr || canvas.height !== rect.height * dpr) {
        canvas.width = rect.width * dpr;
        canvas.height = rect.height * dpr;
    }

    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;

    // 清空背景 & 绘制底色
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = '#1a1a1a';
    ctx.fillRect(0, 0, width, height);

    // --- 2. 计算世界尺寸与摄像机位置 (核心修复逻辑) ---

    // 设定：小地图视野内显示的格子数量（可视范围）
    // 10 代表小地图宽度始终显示 10 个格子的距离，保证不拉伸
    const VIEWPORT_TILES = 10; 

    // 计算单个格子的像素大小 (强制正方形)
    const tileSize = width / VIEWPORT_TILES; 

    // 统计地图总行列数
    let cols = 1;
    let rows = 1;
    let hasTerrain = false;

    if (terrainMap.length > 0) {
        hasTerrain = true;
        rows = terrainMap.length;
        cols = 0;
        terrainMap.forEach(row => cols = Math.max(cols, row.length));
    }

    // 计算地图总的像素尺寸
    const worldPixelWidth = cols * tileSize;
    const worldPixelHeight = rows * tileSize;

    // --- 摄像机定位 ---
    // 默认中心点（如果没有玩家）
    let targetX = worldPixelWidth / 2;
    let targetY = worldPixelHeight / 2;

    // 寻找玩家作为摄像机焦点
    const player = sceneData.find(item => item.type === 'player');
    if (player && player.coords) {
        // 将 0-100 的坐标 转换成 网格索引，再转成 像素坐标
        // 逻辑：coords[0]是百分比 -> 乘以 cols 得到第几列 -> 乘以 tileSize 得到像素X

        let pCol, pRow;
        if (hasTerrain) {
            // 有地形，坐标对齐到网格中心
            pCol = (player.coords[0] / 100) * cols;
            pRow = (player.coords[1] / 100) * rows;
        } else {
            // 无地形，直接按比例
            pCol = (player.coords[0] / 100) * 20; // 假设无地形默认20x20
            pRow = (player.coords[1] / 100) * 20;
        }

        targetX = pCol * tileSize;
        targetY = pRow * tileSize;
    }

    // 计算摄像机左上角坐标 (让玩家处于画布中心)
    // CameraX = 目标点X - 画布一半宽
    let camX = targetX - width / 2;
    let camY = targetY - height / 2;

    // (可选) 边界限制：如果你希望画面不超过地图边缘，取消下面注释
    // 但对于小地图来说，显示周围的虚空通常更好，能让玩家知道到头了
    /* 
    camX = Math.max(0, Math.min(camX, worldPixelWidth - width));
    camY = Math.max(0, Math.min(camY, worldPixelHeight - height));
    // 如果地图比画布还小，强制居中
    if (worldPixelWidth < width) camX = (worldPixelWidth - width) / 2;
    if (worldPixelHeight < height) camY = (worldPixelHeight - height) / 2;
    */

    // --- 3. 绘制地形 ---
    ctx.save();
    // 应用摄像机偏移 (所有的绘制都会自动减去 camX, camY)
    ctx.translate(-camX, -camY);

    // 优化：只绘制视野范围内的地形（剔除不可见部分，提升性能）
    // 计算可见的行/列范围
    const startCol = Math.floor(camX / tileSize);
    const endCol = startCol + VIEWPORT_TILES + 1;
    const startRow = Math.floor(camY / tileSize);
    const endRow = startRow + VIEWPORT_TILES + 1;

    if (hasTerrain) {
        for (let r = Math.max(0, startRow); r < Math.min(rows, endRow); r++) {
            const rowStr = terrainMap[r];
            for (let c = Math.max(0, startCol); c < Math.min(cols, endCol); c++) {
                if (c >= rowStr.length) continue;

                const char = rowStr[c];
                const px = c * tileSize;
                const py = r * tileSize;

                // 使用 +1 消除浏览器渲染产生的微小缝隙
                drawProceduralTile(ctx, char, Math.floor(px), Math.floor(py), Math.ceil(tileSize + 1), Math.ceil(tileSize + 1));
            }
        }
    } else {
        // 无地形时的网格底图
        ctx.fillStyle = '#2e3033';
        ctx.fillRect(0, 0, worldPixelWidth, worldPixelHeight);
        ctx.strokeStyle = 'rgba(255,255,255,0.05)';
        ctx.lineWidth = 1;
        ctx.strokeRect(0, 0, worldPixelWidth, worldPixelHeight);

        ctx.fillStyle = '#666';
        ctx.font = '14px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText("无地形数据", worldPixelWidth/2, worldPixelHeight/2);
    }

    // --- 4. 绘制实体 ---

    sceneData.forEach(item => {
        if (!item.coords || !item.icon || !item.name) return;

        let itemPixelX, itemPixelY;

        if (hasTerrain) {
            // 网格吸附：将 60% 这种坐标 换算成具体的 第N个格子的中心
            const colIndex = (item.coords[0] / 100) * cols; // 比如 0.6 * 20 = 12
            const rowIndex = (item.coords[1] / 100) * rows;

            // 居中偏移：+0.5个格子
            // 这里不取整，如果坐标本身是浮点数，允许平滑移动
            // 如果想要严格格子对齐，可以用 Math.floor(colIndex)
            itemPixelX = colIndex * tileSize; 
            itemPixelY = rowIndex * tileSize; 
        } else {
            itemPixelX = (item.coords[0] / 100) * (cols * tileSize);
            itemPixelY = (item.coords[1] / 100) * (rows * tileSize);
        }

        // 判断是否在视野内 (简单的视锥剔除)
        // 留一点余量 (baseSize * 2) 防止图标切半
        if (itemPixelX < camX - tileSize || itemPixelX > camX + width + tileSize ||
            itemPixelY < camY - tileSize || itemPixelY > camY + height + tileSize) {
            return; 
        }

        // 绘制逻辑
        let baseSize = item.size ? parseInt(item.size) : tileSize * 0.7; // 图标大小约为格子的70%
        const fontSize = isLargeMap ? baseSize * 1.2 : baseSize; 

        // 获取图标字符
        let iconChar = '\uf059'; 
        try {
            const tempIconEl = document.createElement('i');
            tempIconEl.className = `fas ${item.icon}`;
            document.body.appendChild(tempIconEl);
            const content = window.getComputedStyle(tempIconEl, ':before').getPropertyValue('content').replace(/'|"/g, '');
            document.body.removeChild(tempIconEl);
            if (content && content !== 'none') iconChar = content;
        } catch (e) {}

        let color = item.color || '#fff';
        if (!item.color) {
            if (item.type === 'player') color = '#00e676';
            else if (item.type === 'npc') color = '#ffea00';
            else if (item.type === 'exit') color = '#ff4081';
        }

        // 阴影 (基于 itemPixelX, itemPixelY)
        ctx.fillStyle = 'rgba(0,0,0,0.5)';
        ctx.beginPath();
        ctx.ellipse(itemPixelX + tileSize/2, itemPixelY + tileSize/2 + fontSize * 0.3, fontSize * 0.3, fontSize * 0.1, 0, 0, Math.PI * 2);
        ctx.fill();

        // 图标
        ctx.font = `900 ${fontSize}px "Font Awesome 5 Free"`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.lineWidth = 3;
        ctx.strokeStyle = 'rgba(0,0,0,0.8)';
        // 注意：drawImage或text时，坐标在格子中心
        ctx.strokeText(iconChar, itemPixelX + tileSize/2, itemPixelY + tileSize/2);
        ctx.fillStyle = color;
        ctx.fillText(iconChar, itemPixelX + tileSize/2, itemPixelY + tileSize/2);

        // 名牌
        const isScenery = item.type === 'scenery';
        const textFontSize = isLargeMap ? 14 : (isScenery ? 10 : 11);
        ctx.font = `bold ${textFontSize}px "Noto Serif SC", sans-serif`;

        const textMetrics = ctx.measureText(item.name);
        const textW = textMetrics.width + 6;
        const textH = textFontSize + 4;
        // 名牌放在图标下面
        const textY = itemPixelY + tileSize/2 + fontSize/2 + 4; 

        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.beginPath();
        ctx.roundRect(itemPixelX + tileSize/2 - textW/2, textY, textW, textH, 3);
        ctx.fill();

        ctx.fillStyle = '#fff';
        if (item.type === 'player') ctx.fillStyle = '#50fa7b';
        ctx.textBaseline = 'top';
        ctx.fillText(item.name, itemPixelX + tileSize/2, textY + 2);

        // 为互动与点击提供数据反查
        // 保存的是相对于 Canvas 左上角的坐标，所以要减去 camX/camY
        if (canvas.clickAreas) {
             // 这里的rect 是屏幕坐标系
             const screenX = itemPixelX + tileSize/2 - camX;
             const screenY = itemPixelY + tileSize/2 - camY;

             canvas.clickAreas.push({
                // 定义一个稍大一点的点击区域
                rect: {
                    left: screenX - tileSize/2,
                    top: screenY - tileSize/2,
                    right: screenX + tileSize/2,
                    bottom: screenY + tileSize/2 + textH
                },
                item: item
            });
        }
    });

    ctx.restore(); // 恢复 translate 之前的状态
    ctx.restore(); // 恢复 dpr scale 之前的状态

    // 调试：画一个边框表示这是小地图
    if (!isLargeMap) {
        ctx.strokeStyle = 'rgba(255, 215, 0, 0.3)';
        ctx.lineWidth = 2;
        ctx.strokeRect(0, 0, width, height);
    }
}
async function updateMiniMap() {
    const container = document.getElementById('mini-map-container');
    if (!container || container.classList.contains('hidden')) {
        return;
    }

    const canvas = document.getElementById('mini-map-canvas');
    if (!canvas || typeof renderSceneMap !== 'function') {
        return;
    }

    const sceneMapRow = (typeof currentState !== 'undefined' && currentState['10']) ? currentState['10']['SCENE_MAP'] : null;
    const mapConfig = (sceneMapRow && sceneMapRow['1']) ? sceneMapRow['1'] : {};

    await renderSceneMap(canvas, mapConfig);
}

async function applyVariableAndUiUpdates(delta, smallSummary, largeSummary, initialState, logEntry, allLogs, storyContentForVisuals, newsReferenceContent, systemNotifications) {
    const combinedDelta = [...(delta || []), ...achievementRewardDeltas];
    achievementRewardDeltas = [];

    if (combinedDelta.length > 0 || smallSummary !== null || largeSummary !== null) {
        const result = await applyChanges(JSON.parse(JSON.stringify(initialState)), combinedDelta);
        const { newState, characterNameChanges, updatedCharacterIds: localUpdatedIds } = result;
        currentState = newState;

        if (localUpdatedIds && localUpdatedIds.size > 0) {
            let hasNpcUpdate = false;
            localUpdatedIds.forEach(id => {
                if (id === 'B1') {
                    showDanmaku('角色状态更新', 'player');
                } else if (id.startsWith('C') || id.startsWith('G')) {
                    let charName = newState['0']?.[id]?.['1']?.split('|')[0] || initialState['0']?.[id]?.['1']?.split('|')[0] || characterDatabase[id]?.name || id;
                    showDanmaku(`${charName} 状态已更新`, 'npc');
                    updatedCharacterIds.add(id);
                    hasNpcUpdate = true;
                }
            });
            if (hasNpcUpdate) {
                const surroundingBtn = document.getElementById('surrounding-characters-button');
                if (surroundingBtn && !surroundingBtn.querySelector('.red-dot')) {
                    const dot = document.createElement('span');
                    dot.className = 'red-dot';
                    surroundingBtn.appendChild(dot);
                }
            }
        }

        displayVariableDiff(initialState, currentState);
        const diffPopup = document.getElementById('variable-diff-popup');
        if (diffPopup.innerHTML.includes('<li>')) {
            diffPopup.classList.remove('hidden');
            clearTimeout(variableDiffHideTimer);
            variableDiffHideTimer = setTimeout(() => { diffPopup.classList.add('hidden'); }, 3000);
            showDanmaku('AI变量更新完成', 'success');
        }

        await applyAttributeAlignment();

        syncStateFromTables();
        renderPlayerAttributes(currentPlayerData);
        renderInventory(inventoryItems);
        await updateAvatar(currentPlayerData);
        await updateMiniMap();
        checkPlayerDeath();

        if (surroundingCharactersOverlay.classList.contains('visible')) {
            if (characterDetailView.classList.contains('hidden')) {
                renderCharacterList();
            } else if (currentEditingNpcId) {
                const updatedCharData = characterDatabase[currentEditingNpcId];
                if (updatedCharData) showCharacterDetailPanel(updatedCharData, null);
                else showCharacterListView();
            }
        }

        if (summaryConfig.segmentedMemoryEnabled) {
            logEntry.smallSummary = smallSummary || '';
            logEntry.largeSummary = largeSummary || '';
        }

        logEntry.stateSnapshot = JSON.stringify(currentState);

        await autoGenerateCharacterWorldBooks(localUpdatedIds, logEntry, currentState);

        const archive = await db.archives.get(currentArchiveName);
        if (archive) {
            const logIndex = archive.data.logs.findIndex(l => l.id === logEntry.id);
            if (logIndex !== -1) archive.data.logs[logIndex] = logEntry;
            else archive.data.logs.push(logEntry);

            const originalLogCount = archive.data.logs.length;
            archive.data.logs = archive.data.logs.filter(log => !log.isUndoSnapshot);
            if (archive.data.logs.length < originalLogCount) console.log("成功生成新回复，已清理过时的深度记忆备份。");

            await db.archives.put(archive);
            console.log("变量和初步日志已保存到数据库。");
        }
    }

    const backgroundTasks = [];
    const worldEvolutionConfig = await dbGet('CULTIVATION_WORLD_EVOLUTION_API_CONFIG_V1') || {};

    if (worldEvolutionConfig.enableSectEvolution) {
        backgroundTasks.push({ name: '宗门演化', promise: manualSectEvolution(storyContentForVisuals, systemNotifications) });
    }

    backgroundTasks.push({ name: '日报/剧场', promise: callAutomatedAITheater(storyContentForVisuals, newsReferenceContent, logEntry.id) });

    const knowledgeConfig = await dbGet(KNOWLEDGE_SEARCH_API_CONFIG_KEY) || {};
    if (knowledgeConfig.autoGenerateFactionInfo) {
        const apiConfigToUse = { apiUrl: knowledgeConfig.apiUrl, apiKey: knowledgeConfig.apiKey, apiModel: knowledgeConfig.apiModel };
        backgroundTasks.push({ name: '势力分析', promise: generateFactionWorldBooks(storyContentForVisuals, apiConfigToUse, new AbortController(), currentState, knowledgeConfig.factionRules, false) });
    }

    if (worldEvolutionConfig.enabled && lastAiStoryText) {
        backgroundTasks.push({ name: '世界演化', promise: _internalRunWorldEvolution(false, lastAiStoryText) });
    }

    if (backgroundTasks.length === 0) {
        console.log("没有配置任何后台任务，流程结束。");
        return;
    }

    const results = await Promise.allSettled(backgroundTasks.map(t => t.promise));

    let factionUpdates = null;
    let sectUpdates = null;
    let worldEvoUpdates = null;
    let hasBackgroundData = false;

    results.forEach((result, index) => {
        const taskName = backgroundTasks[index].name;
        if (result.status === 'rejected') {
            console.error(`后台任务 '${taskName}' 执行失败:`, result.reason);
            showDanmaku(`后台任务 '${taskName}' 失败`, 'error');
        } else if (result.status === 'fulfilled' && result.value) {
            hasBackgroundData = true;
            if (taskName === '日报/剧场') {
                const theaterResult = result.value;
                if (theaterResult.dailyPaperHtml) logEntry.dailyPaperHtml = theaterResult.dailyPaperHtml;
                if (theaterResult.mapEvents) logEntry.mapEvents = theaterResult.mapEvents;
                if(theaterResult.activeTheaterHTML) {
                    if (!currentState.state) currentState.state = {};
                    currentState.state.activeTheaterHTML = theaterResult.activeTheaterHTML;
                }
            } else if (taskName === '势力分析' && result.value.hasChanges) {
                factionUpdates = result.value.updatesMap;
            } else if (taskName === '宗门演化') {
                sectUpdates = result.value;
            } else if (taskName === '世界演化') {
                worldEvoUpdates = result.value;
            }
        }
    });

    if (!hasBackgroundData) {
        console.log("所有后台任务均未返回有效数据，无需二次保存。");
        return;
    }

    if (sectUpdates) {
        currentState.sectData = deepMerge(currentState.sectData || {}, sectUpdates);
    }

    try {
        const archive = await db.archives.get(currentArchiveName);
        if (archive) {
            const mostRecentBiographies = logEntry.biographySnapshot || [];

            const masterMap = new Map(mostRecentBiographies.map(e => [e.key || e.title, e]));

            if (factionUpdates) {
                factionUpdates.forEach((value, key) => masterMap.set(key, value));
            }
            if (worldEvoUpdates) {
                worldEvoUpdates.forEach(entry => masterMap.set(entry.key || entry.title, entry));
            }

            const finalBiographies = Array.from(masterMap.values());

            logEntry.biographySnapshot = finalBiographies;
            archive.data.state.worldBookEntries = finalBiographies;

            const logIndex = archive.data.logs.findIndex(l => l.id === logEntry.id);
            if (logIndex !== -1) {
                archive.data.logs[logIndex] = logEntry;
            } else {
                archive.data.logs.push(logEntry);
            }

            archive.data.state.currentState = currentState;

            await db.archives.put(archive);

            console.log("后台任务数据已合并并保存到数据库。");

            await updateMiniMap();
            await saveCurrentState(); 
            if (sectUpdates) updateSectHeaderStats();
        }
    } catch (e) {
        console.error("保存后台任务数据时出错:", e);
    }

    (async () => {
        const finalBackgroundTasks = [];
        if (storyContentForVisuals) finalBackgroundTasks.push(extractAndGenerateBackground(storyContentForVisuals));
        finalBackgroundTasks.push(processNpcImages());
        const finalResults = await Promise.allSettled(finalBackgroundTasks);
        finalResults.forEach((result, index) => {
            if (result.status === 'rejected') console.error(`一个最终异步任务失败 (索引 ${index}):`, result.reason);
        });
    })();
}

async function handleBiographySnapshots(archive, initialState, finalState, targetLog) {
    if (!archive || !knowledgeSearchGlobalConfig.attachBiographyToSnapshot) {
        return;
    }

    if (!targetLog) {
        console.error("handleBiographySnapshots 错误: 未提供目标日志条目。");
        return;
    }

    const logs = archive.data.logs || [];
    const targetLogIndex = logs.findIndex(log => log.id === targetLog.id);
    if (targetLogIndex === -1) {
        console.error("handleBiographySnapshots 错误: 在存档中找不到目标日志条目。");
        return;
    }

    const lastLogWithBio = [...logs.slice(0, targetLogIndex)].reverse().find(log => log.biographySnapshot);
    const previousBiographies = lastLogWithBio ? lastLogWithBio.biographySnapshot : [];

    const biographyMasterMap = new Map(previousBiographies.map(e => [e.key, { ...e }]));

    const finalNpcIds = new Set(Object.keys(finalState['0'] || {}).filter(id => id.startsWith('C') || id.startsWith('G')));

    let changesMade = false;

    for (const charId of finalNpcIds) {
        const charData = finalState['0'][charId];
        if (charData) {
            const characterSnapshotContent = getSingleCharacterSnapshot(charId, finalState);
            const charName = charData['1']?.split('|')[0] || charId;
            const existingEntry = biographyMasterMap.get(charId);

            if (existingEntry) {
                if(existingEntry.content !== characterSnapshotContent) {
                    existingEntry.content = characterSnapshotContent;
                    changesMade = true;
                }
            } else {
                 const newEntry = {
                    id: crypto.randomUUID(),
                    key: charId,
                    title: charName,
                    type: '人物',
                    content: characterSnapshotContent,
                    enabled: true,
                    triggerMode: 'green',
                    keywords: [charName],
                    depth: knowledgeSearchGlobalConfig.worldBookSearchDepth || 5,
                };
                biographyMasterMap.set(charId, newEntry);
                changesMade = true;
            }
        }
    }

    archive.data.state.worldBookEntries = Array.from(biographyMasterMap.values());

    targetLog.biographySnapshot = Array.from(biographyMasterMap.values());
    console.log(`[世界档案-快照模式] 传记/世界设定更新完成，并附加到ID为 ${targetLog.id} 的日志上。当前共 ${targetLog.biographySnapshot.length} 条。`);
}

function toggleTheaterPopup(forceShow = false) {
    const theaterWindow = document.getElementById('ai-theater-window');
    if (!theaterWindow) {
        console.error("致命错误：无法找到小剧场弹窗元素 #ai-theater-window！");
        return;
    }

    const isCurrentlyVisible = window.getComputedStyle(theaterWindow).display === 'flex';

    if (forceShow || !isCurrentlyVisible) {
        theaterWindow.style.display = 'flex';
        console.log("AI剧场：弹窗已打开，即将调用 loadLatestTheaterIntoPopup() 来加载内容...");
        loadLatestTheaterIntoPopup();

        const theaterBtn = document.getElementById('toggle-theater-btn');
        if (theaterBtn) {
            const dot = theaterBtn.querySelector('.red-dot');
            if (dot) {
                dot.remove();
            }
        }
    } else {
        theaterWindow.style.display = 'none';
        console.log("AI剧场：弹窗已关闭。");
    }
}

async function loadLatestTheaterIntoPopup() {
    const iframe = document.getElementById('ai-theater-iframe');
    const placeholder = document.getElementById('ai-theater-placeholder');
    const controls = document.getElementById('daily-paper-controls');

    if (!iframe || !placeholder || !controls) {
        console.error("致命错误：无法在页面上找到日报/剧场的关键UI元素！");
        return;
    }

    placeholder.style.display = 'flex';
    iframe.style.display = 'none';
    controls.classList.add('hidden');

    if (!currentArchiveName) {
        placeholder.innerHTML = '<span>请先开始或加载一个存档。</span>';
        return;
    }

    const isDailyPaperMode = localStorage.getItem('theater_isDailyPaperMode') === 'true';

    try {
        const archive = await db.archives.get(currentArchiveName);
        if (!archive) {
            throw new Error("找不到当前存档。");
        }

        if (isDailyPaperMode) {
            const allPaperLogs = (archive.data.logs || []).filter(log => log.dailyPaperHtml);
            if (allPaperLogs.length > 0) {
                const latestLog = allPaperLogs[allPaperLogs.length - 1];
                await renderDailyPaperById(latestLog.id);
            } else {
                placeholder.innerHTML = '<span>当前存档尚无日报内容。</span>';
            }
        } else {
