async function manageKnowledgeSearchPresets() {
    const KNOWLEDGE_PRESETS_KEY = 'CULTIVATION_KNOWLEDGE_PRESETS_V1';

    const renderRules = (type, rules, containerId) => {
        const listEl = document.getElementById(containerId);
        if (!listEl) return;

        listEl.innerHTML = '';
        (rules || []).forEach(rule => {
            const item = document.createElement('div');
            item.className = 'regex-rule-item';
            item.style.opacity = rule.enabled === false ? '0.5' : '1';
            const iconColor = rule.triggerMode === 'blue' ? '#4fc3f7' : '#66bb6a';
            const roleLabel = `[${(rule.role || 'system').toUpperCase()}]`;

            item.innerHTML = `
                <div class="thinking-wb-toggle-container">
                    <label class="switch">
                        <input type="checkbox" class="ks-rule-toggle" data-id="${rule.id}" data-type="${type}" ${rule.enabled !== false ? 'checked' : ''}>
                        <span class="slider round"></span>
                    </label>
                </div>
                <i class="fas fa-lightbulb" style="color: ${iconColor}; margin-right: 8px;" title="触发模式: ${rule.triggerMode === 'blue' ? '时刻触发' : '关键词触发'}"></i>
                <span class="rule-name" title="${rule.name}"><span style="color: #aaa;">${roleLabel}</span> ${rule.name}</span>
                <div class="rule-actions">
                    <button class="ks-rule-edit-btn" data-id="${rule.id}" data-type="${type}"><i class="fas fa-edit"></i></button>
                    ${rule.id.includes('default-rule') ? '<button disabled><i class="fas fa-lock"></i></button>' : `<button class="ks-rule-delete-btn" data-id="${rule.id}" data-type="${type}"><i class="fas fa-trash"></i></button>`}
                </div>
            `;
            listEl.appendChild(item);
        });

        if(!rules || rules.length === 0) {
             if (containerId === 'ks-faction-rules-list') {
                 listEl.innerHTML = '<p style="text-align: center; opacity: 0.7;">暂无规则，请添加或恢复默认。</p>';
             }
        }
    };

    const presetsData = await dbGet(KNOWLEDGE_PRESETS_KEY) || { presets: [] };
    const activePreset = presetsData.presets.find(p => p.id === presetsData.activePresetId);

    renderRules('faction', knowledgeSearchGlobalConfig.factionRules || [], 'ks-faction-rules-list');

    const handleListClick = async (e, type) => {
        const button = e.target.closest('button');
        const toggle = e.target.closest('.ks-rule-toggle');
        let rulesToUpdate, dbKeyToUpdate, dataToUpdate;

        if (type === 'faction') {
            rulesToUpdate = knowledgeSearchGlobalConfig.factionRules || [];
            dbKeyToUpdate = 'CULTIVATION_KNOWLEDGE_SEARCH_API_CONFIG_V2';
            dataToUpdate = knowledgeSearchGlobalConfig;
        } else {
            return;
        }

        if (toggle) {
            const ruleId = toggle.dataset.id;
            const rule = rulesToUpdate.find(r => r.id === ruleId);
            if(rule) {
                rule.enabled = toggle.checked;
                await dbSet(dbKeyToUpdate, dataToUpdate);
                renderRules(type, rulesToUpdate, `ks-${type}-rules-list`);
            }
            return;
        }

        if (!button) return;

        const ruleId = button.dataset.id;

        if (button.classList.contains('ks-rule-edit-btn')) {
            currentEditingContext.type = `ks-${type}`;
            openWorldBookEditor(ruleId);
        } else if (button.classList.contains('ks-rule-delete-btn')) {
            const ruleIndex = rulesToUpdate.findIndex(r => r.id === ruleId);
            if (ruleIndex > -1 && await showCustomConfirm('确定要删除此规则吗？')) {
                rulesToUpdate.splice(ruleIndex, 1);
                await dbSet(dbKeyToUpdate, dataToUpdate);
                renderRules(type, rulesToUpdate, `ks-${type}-rules-list`);
            }
        }
    };

    const factionList = document.getElementById('ks-faction-rules-list');
    if (factionList && !factionList.dataset.listener) {
        factionList.addEventListener('click', (e) => handleListClick(e, 'faction'));
        factionList.dataset.listener = 'true';
    }
}

