async function openWorldBookEditor(id = null) {
    const KNOWLEDGE_PRESETS_KEY = 'CULTIVATION_KNOWLEDGE_PRESETS_V1';

    if (!id && !currentEditingContext.type) {
        showCustomAlert('错误：无法确定要创建的条目类型。');
