        focusFilterBtn.innerHTML = `<i class="${worldBookShowFocusOnly ? 'fas' : 'far'} fa-eye"></i> ${worldBookShowFocusOnly ? '只看关注' : '全部条目'}`;
        focusFilterBtn.onclick = () => {
