        sortNameBtn.innerHTML = `名称 ${worldBookSortBy === 'name' ? (worldBookSortOrder === 'asc' ? '<i class="fas fa-sort-alpha-down"></i>' : '<i class="fas fa-sort-alpha-up"></i>') : ''}`;
        sortNameBtn.onclick = () => {
            if (worldBookSortBy === 'name') {
                worldBookSortOrder = worldBookSortOrder === 'asc' ? 'desc' : 'asc';
            } else {
                worldBookSortBy = 'name';
                worldBookSortOrder = 'asc';
            }
            renderWorldBookEntries(filterType);
