                }

                // 构建列表项：移除收藏按钮，保留关注按钮(仅人物)
                itemEl.innerHTML = `
                    <input type="checkbox" class="summary-checkbox" data-id="${entry.id}" style="margin-right: 15px; transform: scale(1.2); cursor: pointer;">
