            const uploadBtn = document.createElement('button');
            uploadBtn.className = 'action-btn';
            uploadBtn.title = '上传至云端';
            uploadBtn.innerHTML = '<i class="fas fa-cloud-upload-alt"></i>';
            uploadBtn.onclick = (e) => {
                e.stopPropagation();
