function formatSectDataForAI(sectData) {
    if (!sectData || !sectData.name) {
        return '无宗门数据';
    }

    const parts = [];

    parts.push(
        `# 宗门总览\n- 名称: ${sectData.name}\n- 等级: ${sectData.level || 1}\n- 声望: ${sectData.prestige || 0}\n- 资金: ${sectData.funds || 0} 灵石\n- 描述: ${sectData.description || '暂无描述'}\n- 宗旨: ${sectData.tenet || '尚未确立'}\n- 位置: ${sectData.location || '位置不明'}`
    );

    parts.push(`## 友好势力\n- ${sectData.friendlyForces && sectData.friendlyForces.length > 0 ? sectData.friendlyForces.join('\n- ') : '暂无'}`);
    parts.push(`## 敌对势力\n- ${sectData.hostileForces && sectData.hostileForces.length > 0 ? sectData.hostileForces.join('\n- ') : '暂无'}`);

    const allMemberIds = new Set();
    if (sectData.positions && Array.isArray(sectData.positions)) {
        sectData.positions.forEach(p => {
            if (p.members && Array.isArray(p.members)) {
                p.members.forEach(id => allMemberIds.add(id));
            }
        });
    }

    let membersText = '## 成员列表\n';
    if (allMemberIds.size > 0) {
        let memberLines = [];
        allMemberIds.forEach(id => {
            const charData = currentState['0']?.[id];
            if (charData) {
                const discipleData = (sectData.disciples || []).find(d => d.id === id) || {};
                const positionData = (sectData.positions || []).find(p => p.members && p.members.includes(id));
                const positionTitle = positionData ? positionData.title : '无职位';
                const charName = (charData['1'] || '|').split('|')[0] || `ID: ${id}`;
                const realm = (charData['2'] || '|').split('|')[0] || '境界未知';
                memberLines.push(`- ${charName}(${positionTitle}), 境界: ${realm}, 贡献: ${discipleData.contribution || 0}`);
            }
        });
        membersText += memberLines.length > 0 ? memberLines.join('\n') : '- 暂无成员信息';
    } else {
        membersText += '- 暂无成员';
    }
    parts.push(membersText);

    let positionsText = '## 职位设置\n';
    if (sectData.positions && sectData.positions.length > 0) {
        positionsText += '| 职位名 | 人数 | 月俸 (灵石/月) | 职责 |\n|---|---|---|---|\n';
        sectData.positions.forEach(p => {
            positionsText += `| ${p.title} | ${p.members ? p.members.length : 0} / ${p.max || '不限'} | ${p.salary || 0} | ${p.duties || (p.permissions?.join(',') || '无')} |\n`;
        });
    } else {
        positionsText += '尚未设立任何职位。';
    }
    parts.push(positionsText.trim());

    let tasksText = '## 待处理任务\n';
    const pendingTasks = sectData.tasks ? Object.values(sectData.tasks).filter(t => t && t.status !== 'completed') : [];
    if (pendingTasks.length > 0) {
        pendingTasks.forEach(t => {
            tasksText += `- **任务**: ${t.title || '无标题'} (ID: ${t.id}, 状态: ${t.status || '未知'})\n  - **描述**: ${t.desc || '无'}\n  - **奖励**: ${t.reward || '无'}\n  - **惩罚**: ${t.punishment || '无'}\n  - **要求**: ${t.minRealm || '无'}\n`;
        });
    } else {
        tasksText += '- 暂无';
    }
    parts.push(tasksText.trim());

    let territoryText = '## 宗门建筑\n';
    const buildingKeys = sectData.territory ? Object.keys(sectData.territory).filter(key => key !== 'map' && sectData.territory[key]?.level > 0) : [];
    if (buildingKeys.length > 0) {
        buildingKeys.forEach(key => {
            const building = sectData.territory[key];
            territoryText += `- **${building.name || key} (等级 ${building.level})**: ${building.effect || building.description}\n`;
        });
    } else {
        territoryText += '- 暂无建筑。\n';
    }

    parts.push(territoryText.trim());

    let herbText = '## 药园\n';
    if (sectData.herbGarden && sectData.herbGarden.length > 0) {
        sectData.herbGarden.forEach(herb => {
             const maturityRate = ((Date.now() - new Date(herb.plantingTime).getTime()) / ((herb.maturityCycleHours || 24) * 3600000) * 100).toFixed(0);
             herbText += `- **${herb.name}** (ID: ${herb.id})\n  - 数量: ${herb.count || 1}\n  - 种植时间: ${herb.plantingTime}\n  - 成熟周期: ${herb.maturityCycleHours || 24}小时\n  - 当前阶段: ${herb.currentStage || '未知'}\n  - 成熟度: ${Math.min(100, maturityRate)}%\n`;
        });
    } else {
        herbText += '- 暂无\n';
    }
    parts.push(herbText.trim());

    let beastText = '## 护山灵兽\n';
    if (sectData.guardianBeasts && sectData.guardianBeasts.length > 0) {
        sectData.guardianBeasts.forEach(beast => {
            beastText += `- **${beast.name}** (等级: ${beast.level})\n  - ID: ${beast.id}\n  - 状态: ${beast.status}\n  - 忠诚度: ${beast.loyalty || 80}\n  - 能力: ${beast.ability || '未知'}\n`;
        });
    } else {
        beastText += '- 暂无。\n ';
    }
    parts.push(beastText.trim());

    let warehouseText = '## 宝库\n';
    if (sectData.warehouse && sectData.warehouse.length > 0) {
        sectData.warehouse.forEach(item => {
            warehouseText += `- **${(item.name || '未知物品').replace(/<[^>]+>/g, '')}** (数量: ${item.count || item.quantity || 1})\n  - ID: ${item.id}\n  - 类型: ${item.type || '未知'}\n  - 品阶: ${item.grade || '凡品'}\n  - 描述: ${item.description || '无'}\n  - 来源: ${item.source || '未知'}\n`;
        });
    } else {
        warehouseText += '- 暂无\n ';
    }
    parts.push(warehouseText.trim());

    let libraryText = '## 藏经阁\n';
    if (sectData.library && sectData.library.length > 0) {
        sectData.library.forEach(item => {
            libraryText += `- **《${(item.name || '未知秘籍').replace(/<[^>]+>/g, '')}》**\n  - ID: ${item.id}\n  - 类型: ${item.type || '功法'}\n  - 品阶: ${item.grade || '不入流'}\n  - 描述: ${item.description || '无'}\n  - 兑换所需贡献: ${item.contributionCost}\n`;
        });
    } else {
        libraryText += '- 暂无\n  ';
    }
    parts.push(libraryText.trim());

    let activitiesText = '## 近期日志\n';
    if (sectData.activities && sectData.activities.length > 0) {
        const sortedActivities = [...sectData.activities]
            .sort((a, b) => {
                const dateA = parseGameTime(a.timestamp);
                const dateB = parseGameTime(b.timestamp);
                if (!dateA) return 1;
                if (!dateB) return -1;
                return dateB.getTime() - dateA.getTime();
            })
            .slice(0, 10);

        sortedActivities.forEach(activity => {
            let timestamp = '时间未知';
            if (activity.timestamp) {
                const match = activity.timestamp.match(/(\d{4})年\s*(\d{1,2})月\s*(\d{1,2})日\s*(\d{1,2}):(\d{1,2})/);
                if(match){
                     const [, year, month, day, hour, minute] = match;
                     timestamp = `${year}/${String(month).padStart(2, '0')}/${String(day).padStart(2, '0')} ${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
                } else {
                    timestamp = activity.timestamp;
                }
            }
            activitiesText += `- [${timestamp}] ${activity.description}\n`;
        });
    } else {
        activitiesText += '- 暂无日志';
    }
    parts.push(activitiesText.trim());

    return parts.join('\n\n');
}


