function normalizeSectData(sectData) {
    if (!sectData || !sectData.positions || !Array.isArray(sectData.positions)) {
        return sectData;
    }

    const isOldFormat = sectData.positions.length > 0 && sectData.positions[0].name && !sectData.positions[0].id;

    if (isOldFormat) {
        console.log("检测到旧版宗门职位格式，正在进行兼容性转换...");

        const positionIdMap = {
            '宗主': 'sect_leader',
            '长老': 'elder',
            '内门弟子': 'inner_disciple',
            '外门弟子': 'outer_disciple'
        };

        const newPositions = sectData.positions.map((oldPos, index) => {
            const newPos = { ...oldPos };
            newPos.title = oldPos.name;
            newPos.id = positionIdMap[oldPos.name] || `pos_${index}`;

            const members = sectData.disciples
                .filter(d => d.position === oldPos.name)
                .map(d => d.id);

            newPos.members = members;
            delete newPos.name; 
            delete newPos.count;
            return newPos;
        });

        sectData.positions = newPositions;
    }

    (sectData.activities || []).forEach(activity => {
        if (!activity.id) {
            activity.id = `activity_${crypto.randomUUID()}`;
        }
    });

    return sectData;
}

