function renderSectLog(logItems, container) {
    if (!container) return;

    const logs = logItems ? Object.values(logItems) : [];

    if (logs.length === 0) {
        container.innerHTML = '<div style="flex-grow: 1; display: flex; align-items: center; justify-content: center; color: var(--text-secondary);">暂无宗门日志。</div>';
        return;
    }

    const sortedLogs = logs.sort((a, b) => {
        const dateA = parseGameTime(a.timestamp);
        const dateB = parseGameTime(b.timestamp);
        if (!dateA) return 1;
        if (!dateB) return -1;
        return dateB.getTime() - dateA.getTime();
    }).slice(0, 10);

    let listHtml = '<div class="sect-log-list" style="display: flex; flex-direction: column;">';

    sortedLogs.forEach(entry => {
        if (!entry) return;

        let timestamp = '时间未知';
        if (entry.timestamp) {
            const match = entry.timestamp.match(/(\d{4})年\s*(\d{1,2})月\s*(\d{1,2})日\s*(\d{1,2}):(\d{1,2})/);
            if (match) {
                const [, year, month, day, hour, minute] = match;
                timestamp = `${year}/${String(month).padStart(2, '0')}/${String(day).padStart(2, '0')} ${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
            } else {
                timestamp = entry.timestamp; 
            }
        }

        const description = entry.description || '无具体内容';

        listHtml += `
            <div class="sect-log-item">
                <div class="sect-log-timestamp">${timestamp}</div>
                <div class="sect-log-content">${description}</div>
            </div>
        `;
    });

    listHtml += '</div>';
    container.innerHTML = `<div style="flex-grow: 1; overflow-y: auto; min-height: 0;">${listHtml}</div>`;
}
function parseGameTime(gameTimeString) {
    if (!gameTimeString) return null;
    const match = gameTimeString.match(/(\d{4})年\s*(\d{1,2})月\s*(\d{1,2})日\s*(\d{1,2}):(\d{1,2})/);
    if (match) {
        const [, year, month, day, hour, minute] = match;
        return new Date(year, parseInt(month) - 1, day, hour, minute);
    }
    const date = new Date(gameTimeString);
    if (!isNaN(date.getTime())) {
        return date;
    }
    return null;
}

function showDiscipleContextMenu(discipleId, buttonElement) {
