    if (existingMenu) existingMenu.remove();

    const menu = document.createElement('div');
    menu.id = 'disciple-context-menu';
    menu.className = 'disciple-context-menu';

    Object.assign(menu.style, {
        position: 'fixed',
        zIndex: '10005',
        width: '140px',
        boxShadow: '0 4px 15px rgba(0,0,0,0.8)',
        backgroundColor: '#2c2a2a',
        border: '1px solid var(--primary-color)',
        borderRadius: '6px',
        padding: '5px 0'
    });

    const getBestName = () => {
        if (typeof allBiographyEntries !== 'undefined') {
            const bio = allBiographyEntries.find(b => b.key === discipleId);
            if (bio) {
                try {
                    const p = JSON.parse(bio.content);
                    if (p['1']) return p['1'].split('|')[0];
                } catch(e) {}
                if (bio.title) return bio.title;
            }
        }
        if (currentState['0'] && currentState['0'][discipleId]) {
            return currentState['0'][discipleId]['1'].split('|')[0];
        }
        if (typeof characterDatabase !== 'undefined' && characterDatabase[discipleId]) {
            return characterDatabase[discipleId].name;
        }
        if (currentState.sectData.disciples) {
            const d = currentState.sectData.disciples.find(x => x.id === discipleId);
            if (d && d.name) return d.name;
        }
        return `ID:${discipleId}`;
    };

    const sectData = currentState.sectData;
    let currentPositionTitle = '无职位';
    const currentPosition = sectData.positions.find(p => p.members && p.members.includes(discipleId));
    if (currentPosition) {
        currentPositionTitle = currentPosition.title;
    }

    const playerPosition = sectData.positions?.find(p => p.members?.includes('B1'));
    const canManage = playerPosition?.permissions?.includes('all') || playerPosition?.permissions?.includes('manage_members');

    if (canManage && discipleId !== 'B1') {
        const availablePositions = sectData.positions
            .filter(p => !p.permissions?.includes('all') && p.title !== currentPositionTitle)
            .map(p => p.title);

        if (availablePositions.length > 0) {
            const header = document.createElement('div');
            header.textContent = '职位变更...';
            header.style.cssText = 'padding:8px 12px; color:#888; font-size:0.8em; border-bottom:1px solid #444;';
            menu.appendChild(header);

            availablePositions.forEach(posName => {
                const btn = document.createElement('button');
                btn.innerHTML = `<i class="fas fa-exchange-alt fa-fw"></i> ${posName}`;
                btn.onclick = async () => {
                    const charName = getBestName();

                    if (currentPosition) {
                        currentPosition.members = currentPosition.members.filter(m => m !== discipleId);
                    }
                    const newPosition = sectData.positions.find(p => p.title === posName);
                    if (newPosition) {
                        if (!newPosition.members) newPosition.members = [];
                        newPosition.members.push(discipleId);
                    }

                    const timeRowData = Array.isArray(currentState['4']) ? currentState['4'].find(row => row.id === TIME_LOCATION_ROW_ID) : (currentState['4'] ? currentState['4'][0] : null);
                    const gameTime = timeRowData ? (timeRowData['0'] || '').split('/')[0].trim() : "时间未知";

                    if (!sectData.activities) sectData.activities = [];
                    sectData.activities.push({
                        id: crypto.randomUUID(),
                        timestamp: gameTime,
                        description: `弟子 ${charName} 的职位从 [${currentPositionTitle}] 变更为 [${posName}]。`
                    });

                    await saveCurrentState();
                    showDanmaku(`已将 ${charName} 调任至 ${posName}`, 'success');

                    const container = document.getElementById('sect-pane-disciples');
                    if (container) {
                         await renderSectDisciples(sectData.disciples, container);
                    }
                    menu.remove();
                };
                menu.appendChild(btn);
            });
        }
    }

    const viewBtn = document.createElement('button');
    viewBtn.innerHTML = `<i class="fas fa-id-card fa-fw"></i> 查看面板`;
    viewBtn.onclick = () => {
        let charDataStr = null;
        if (currentState['0'][discipleId]) {
            charDataStr = JSON.stringify(currentState['0'][discipleId]);
        } 
        else if (typeof allBiographyEntries !== 'undefined') {
             const bio = allBiographyEntries.find(b => b.key === discipleId);
             if (bio) charDataStr = bio.content;
        }

        if (charDataStr) {
            openWorldBookCharacterPanel({ content: charDataStr });
            menu.remove();
        } else {
            showCustomAlert('错误：找不到该成员的详细数据(未在场景或档案中)。');
        }
    };
    menu.appendChild(viewBtn);

    if (discipleId === 'B1') {
        const exitBtn = document.createElement('button');
        exitBtn.innerHTML = `<i class="fas fa-sign-out-alt fa-fw"></i> 退出宗门`;
        exitBtn.style.color = '#e57373';
        exitBtn.onclick = async () => {
            if (await showCustomConfirm('确定要退出宗门吗？')) {
                addToInput('我决定退出宗门');
                closeSectSystem();
                menu.remove();
            }
        };
        menu.appendChild(exitBtn);
    } else if (canManage) {
        const kickBtn = document.createElement('button');
        kickBtn.innerHTML = `<i class="fas fa-door-open fa-fw"></i> 移出宗门`;
        kickBtn.style.color = '#e57373';
        kickBtn.onclick = async () => {
            const charName = getBestName();

            if (await showCustomConfirm(`确定要将 <span style="color:#ffd700">${charName}</span> 移出宗门吗？`)) {
                if (currentState.sectData.disciples) {
                    currentState.sectData.disciples = currentState.sectData.disciples.filter(d => d.id !== discipleId);
                }
                if (currentState.sectData.positions) {
                    currentState.sectData.positions.forEach(p => {
                        if (p.members) {
                            p.members = p.members.filter(m => m !== discipleId);
                        }
                    });
                }

                const timeRowData = Array.isArray(currentState['4']) ? currentState['4'].find(row => row.id === TIME_LOCATION_ROW_ID) : (currentState['4'] ? currentState['4'][0] : null);
                const gameTime = timeRowData ? (timeRowData['0'] || '').split('/')[0].trim() : "时间未知";

                if (!currentState.sectData.activities) currentState.sectData.activities = [];
                currentState.sectData.activities.push({
                    id: crypto.randomUUID(),
                    timestamp: gameTime,
                    description: `弟子 ${charName} 已被移出宗门。`
                });

                await saveCurrentState();
                showDanmaku(`${charName} 已被移出宗门`, 'success');

                const container = document.getElementById('sect-pane-disciples');
                if (container) {
                    await renderSectDisciples(currentState.sectData.disciples, container);
                }
                menu.remove();
            }
        };
        menu.appendChild(kickBtn);
    }

    document.body.appendChild(menu);
    const rect = buttonElement.getBoundingClientRect();
    const menuWidth = 140;

    let leftPos = rect.left - menuWidth + rect.width;
    if (leftPos < 10) leftPos = rect.left; 

    let topPos = rect.bottom + 5;

    if (topPos + menu.offsetHeight > window.innerHeight) {
        topPos = rect.top - menu.offsetHeight - 5;
    }

    menu.style.top = `${topPos}px`;
    menu.style.left = `${leftPos}px`;

    const closeMenu = (event) => {
        if (!menu.contains(event.target) && !buttonElement.contains(event.target)) {
            menu.remove();
            document.removeEventListener('click', closeMenu, true);
        }
    };
    setTimeout(() => {
        document.addEventListener('click', closeMenu, true);
    }, 0);
}


function openSectDisciplePicker() {
    const existingDiscipleIds = new Set((currentState.sectData?.disciples || []).map(d => d.id));
    const potentialRecruits = surroundingCharacters.filter(char => !existingDiscipleIds.has(char.id));

    pickerTitle.textContent = '选择要招入宗门的弟子';
    const pickerGrid = document.getElementById('picker-grid');
    pickerGrid.innerHTML = '';
    pickerGrid.style.display = 'flex';
    pickerGrid.style.flexDirection = 'column';
    pickerGrid.style.gap = '10px';

    if (potentialRecruits.length === 0) {
        pickerGrid.innerHTML = '<p style="text-align:center;">周围没有可招收的弟子。</p>';
        pickerOverlay.classList.add('visible');
        return;
    }

    let formHtml = '<div style="display: flex; flex-wrap: wrap; gap: 15px; justify-content: center;">';
    potentialRecruits.forEach(char => {
        formHtml += `
            <label style="display: flex; align-items: center; cursor: pointer; padding: 10px 15px; border-radius: 6px; background: rgba(255,255,255,0.05); border: 1px solid var(--separator-color); transition: all 0.2s;">
                <input type="checkbox" value="${char.id}" data-name="${char.name}" style="margin-right: 10px; transform: scale(1.3);">
                <span>${char.name} (${char.realm})</span>
            </label>
        `;
    });
    formHtml += '</div>';

    const buttonContainer = document.createElement('div');
    buttonContainer.style.marginTop = '20px';
    buttonContainer.style.textAlign = 'center';

    const confirmBtn = document.createElement('button');
    confirmBtn.className = 'major-action-button';
    confirmBtn.textContent = '确认招收';
    confirmBtn.style.padding = '12px 30px'; 
    confirmBtn.onclick = () => {
        const selectedCheckboxes = pickerGrid.querySelectorAll('input:checked');
        if (selectedCheckboxes.length > 0) {
            const selectedNames = Array.from(selectedCheckboxes).map(cb => cb.dataset.name);
            const commandString = `我决定将 ${selectedNames.join('、')} 招入宗门。`;
            addToInput(commandString);
            closeEquipmentPicker(); 
            closeSectSystem(); 
        } else {
            showCustomAlert('请至少选择一名弟子。');
        }
    };

    pickerGrid.innerHTML = formHtml;
    buttonContainer.appendChild(confirmBtn);
    pickerGrid.appendChild(buttonContainer);

    pickerOverlay.classList.add('visible');
}
function showDangerConfirm(reqRealm, playerRealm) {
    return new Promise((resolve) => {
        const overlay = document.createElement('div');
        overlay.id = 'danger-confirm-overlay';
        overlay.innerHTML = `
            <div class="danger-confirm-box">
                <div class="danger-title"><i class="fas fa-exclamation-triangle"></i> 境界警告</div>
                <p style="color: #ccc; font-size: 1.1em; margin-bottom: 10px;">此任务极其凶险！</p>
                <div style="background:rgba(0,0,0,0.5); padding:10px; border-radius:4px; margin-bottom:20px; border:1px dashed #555;">
                    <p style="margin:5px 0; color:#888;">你的境界: <span style="color:#e57373">${playerRealm}</span></p>
                    <p style="margin:5px 0; color:#888;">推荐境界: <span style="color:#ef5350; font-weight:bold;">${reqRealm}</span></p>
                </div>
                <p style="color:#ff8a80; font-size:0.9em; margin-bottom:25px;">强行接取可能导致重伤甚至<strong>道消身死</strong>，确定要富贵险中求吗？</p>
                <div style="display:flex; gap:15px; justify-content:center;">
                    <button id="danger-cancel-btn" class="major-action-button" style="border-color:#777; color:#ccc;">惜命放弃</button>
                    <button id="danger-confirm-btn" class="major-action-button" style="background:#d32f2f; border-color:#ff5252; color:white; box-shadow: 0 0 10px rgba(211, 47, 47, 0.5);">
                        <i class="fas fa-skull"></i> 拼死一搏
                    </button>
                </div>
            </div>
        `;
        document.body.appendChild(overlay);

        const box = overlay.querySelector('.danger-confirm-box');
        const cancelBtn = document.getElementById('danger-cancel-btn');
        const confirmBtn = document.getElementById('danger-confirm-btn');

        cancelBtn.onclick = () => {
            overlay.style.opacity = '0';
            setTimeout(() => overlay.remove(), 200);
            resolve(false);
        };

        confirmBtn.onclick = () => {
            box.classList.add('shattering');
            setTimeout(() => {
                overlay.style.opacity = '0';
                setTimeout(() => {
                    overlay.remove();
                    resolve(true);
                }, 100);
            }, 350);
        };
    });
}

function renderSectTasks(tasks, container) {
    if (!container || !currentState.sectData) return;

    const sectData = currentState.sectData;
    const playerPosition = sectData.positions?.find(p => p.members?.includes('B1'));

    // 即使不看权限删除，原来的“发布任务”按钮还是保留原有逻辑比较合理，或者你想完全放开也可以，
    // 这里暂时只针对您的要求：放开“删除”权限。发布权限保持原样。
    let canManage = false;
    if (playerPosition) {
        const superAdminTitles = ['宗主', '太上长老', '副宗主'];
        canManage = playerPosition.permissions?.includes('all') ||
                    playerPosition.permissions?.includes('manage_tasks') ||
                    superAdminTitles.includes(playerPosition.title);
    }

    let buttonHtml = '';
    if (canManage) {
        buttonHtml = `
            <div style="text-align: right; margin-bottom: 15px; flex-shrink: 0;">
                <button id="add-sect-task-btn" class="major-action-button small-font-btn">
                    <i class="fas fa-plus"></i> 发布宗门任务
                </button>
            </div>
        `;
    }

    let contentHtml = '';
    const allTasks = tasks ? (Array.isArray(tasks) ? tasks : Object.values(tasks)) : [];

    // 暂时不过滤失败的任务，让用户可以看到并手动删除
    const pendingTasks = allTasks.filter(t => t);

    if (pendingTasks.length === 0) {
        contentHtml = '<div style="flex-grow:1; display:flex; align-items:center; justify-content:center; color:#666;">暂无宗门任务</div>';
    } else {
        const REALM_RANKS = { '凡人': 0, '炼气': 1, '筑基': 2, '结丹': 3, '金丹': 3, '元婴': 4, '化神': 5, '炼虚': 6, '合体': 7, '大乘': 8, '渡劫': 9 };
        const playerRealmStr = (currentPlayerData.realm || '凡人').split('|')[0];
        let playerRankScore = 0;
        for (const key in REALM_RANKS) {
            if (playerRealmStr.includes(key)) {
                playerRankScore = REALM_RANKS[key];
                break;
            }
        }

        let listHtml = pendingTasks.map(t => {
            if (!t) return '';

            const status = t.status || (t.progress ? 'in-progress' : 'available');
            const minRealm = t.minRealm || '炼气初期';

            let rewardText = t.reward;
            if (!rewardText && t.rewards) {
                 const parts = [];
                 if (t.rewards.contribution) parts.push(`${t.rewards.contribution}贡献`);
                 if (t.rewards.funds) parts.push(`${t.rewards.funds}灵石`);
                 if (t.rewards.items && Array.isArray(t.rewards.items)) {
                     parts.push(t.rewards.items.map(i => i.name).join('、'));
                 }
                 rewardText = parts.join('，');
            }
            if (!rewardText) rewardText = '无';

            let statusBadge = '';
            let actionBtn = '';
            let timeHtml = '';

            if (t.endTime && status === 'available') {
                timeHtml = `<div style="font-size:0.8em; color:#888; margin-top:5px;"><i class="fas fa-hourglass-half"></i> 截止: ${t.endTime}</div>`;
            }

            let reqRankScore = 0;
            if (minRealm && minRealm !== '无') {
                for (const key in REALM_RANKS) {
                    if (minRealm.includes(key)) {
                        reqRankScore = REALM_RANKS[key];
                        break;
                    }
                }
            }

            const isRealmMet = playerRankScore >= reqRankScore;
            const cardClass = isRealmMet ? '' : 'danger-task';
            const requirementStyle = isRealmMet ? 'color:#81c784;' : 'color:#ef5350; font-weight:bold;';
            const requirementIcon = isRealmMet ? '' : '<i class="fas fa-skull" style="margin-right:5px;"></i> ';

            let progressHtml = '';

            if (status === 'in-progress' || status === 'completed') {
                let assigneeName = t.assignee || 'B1'; 
                if (assigneeName === 'B1') {
                    assigneeName = (currentPlayerData.name || '我').split('|')[0];
                } else if (assigneeName.startsWith('C') || assigneeName.startsWith('G')) {
                    assigneeName = (characterDatabase[assigneeName]?.name || '同门');
                } else if (!t.assignee) {
                    assigneeName = (currentPlayerData.name || '我').split('|')[0];
                }

                const progressStr = String(t.progress || '进行中');
                const numProgress = t.numericProgress !== undefined ? t.numericProgress : (progressStr.includes('%') ? parseFloat(progressStr) : 0);

                progressHtml = `
                    <div style="margin-top: 10px; background: rgba(0,0,0,0.3); border-radius: 4px; padding: 6px;">
                        <div style="display:flex; justify-content:space-between; font-size:0.8em; color:#ccc; margin-bottom:4px;">
                            <span><i class="fas fa-tasks"></i> ${progressStr}</span>
                            <span style="color:#ffca28; font-weight:bold;">${numProgress}%</span>
                        </div>
                        <div class="beast-bar" style="height:6px; border:none; background:#333;">
                            <div class="beast-bar-fill" style="width:${Math.min(100, numProgress)}%; background:linear-gradient(90deg, #ffca28, #ff6f00);"></div>
                        </div>
                    </div>`;

                if ((t.readyToSubmit === true || status === 'completed') && (t.assignee === 'B1' || !t.assignee)) {
                    statusBadge = `<div class="sect-task-status" style="color:#66bb6a; font-weight:bold;">✅ 待提交</div>`;
                    actionBtn = `
                        <button class="major-action-button submit-task-btn" 
                                data-task-id="${t.id}"
                                style="margin-top:10px; width:100%; background:linear-gradient(90deg, #43a047, #2e7d32); border-color:#66bb6a; color:white;">
                                <i class="fas fa-check-circle"></i> 提交任务领取奖励
                        </button>`;
                } else if (t.assignee === 'B1' || !t.assignee) {
                    statusBadge = `<div class="sect-task-status" style="color:#ffca28;">${assigneeName} 执行中</div>`;
                    actionBtn = `
                        <button class="major-action-button abandon-task-btn" 
                                data-task-id="${t.id}"
                                data-task-title="${t.title}"
                                style="margin-top:10px; width:100%; border-color: #e57373; color: #e57373;">
                                <i class="fas fa-times-circle"></i> 放弃任务
                        </button>`;
                } else {
                    statusBadge = `<div class="sect-task-status" style="color:#aaa;">${assigneeName} 执行中</div>`;
                }

            } else if (status === 'available') {
                statusBadge = '<div class="sect-task-status" style="color:#66bb6a;">可接取 <i class="fas fa-chevron-down sect-task-arrow"></i></div>';

                const btnClass = isRealmMet ? '' : 'danger-accept-btn';
                const btnText = isRealmMet ? '接取任务' : '⚠️ 强行接取 (危险)';

                actionBtn = `<button class="major-action-button accept-task-btn ${btnClass}" 
                                    data-task-id="${t.id}"
                                    data-task-title="${t.title}" 
                                    data-req-realm="${minRealm}"
                                    data-is-met="${isRealmMet}"
                                    style="margin-top:10px; width:100%;">${btnText}</button>`;
            }

            // 在 header 中加入删除按钮
            const deleteButtonHtml = `
                <button class="delete-sect-task-btn" data-task-id="${t.id}" title="删除任务" style="background: transparent; border: none; color: #666; cursor: pointer; margin-right: 10px; font-size: 1.1em; transition: color 0.2s;">
                    <i class="fas fa-trash-alt"></i>
                </button>
            `;

            return `
            <div class="sect-card sect-task-card ${cardClass}" data-status="${status}" style="padding: 0; cursor:pointer;" data-task-id="${t.id}">
                <div class="sect-task-header" style="padding: 12px; display:flex; justify-content:space-between; align-items:center;">
                    <div style="display:flex; flex-direction:column;">
                        <span class="sect-task-title">${isRealmMet ? '' : '⚠️ '}${t.title}</span>
                        ${timeHtml}
                    </div>
                    <div style="display:flex; align-items:center;">
                        ${deleteButtonHtml}
                        ${statusBadge}
                    </div>
                </div>
                <div class="sect-task-body" style="display:none; padding: 0 12px 12px 12px; border-top:1px dashed rgba(140, 120, 83, 0.3); margin-top:0;">
                    <div style="height: 10px;"></div>
                    <p style="font-size:0.9em; color:var(--text-secondary); margin:5px 0;">${t.desc || t.description || '暂无描述'}</p>
                    <div style="font-size:0.85em; margin-top:8px; display:flex; justify-content:space-between; align-items:center;">
                        <span class="sect-task-reward"><i class="fas fa-gift"></i> ${rewardText}</span>
                        <span style="${requirementStyle}">
                            ${requirementIcon}需: ${minRealm}
                        </span>
                    </div>
                    ${progressHtml}
                    ${actionBtn}
                </div>
            </div>`;
        }).join('');
        contentHtml = `<div style="flex-grow: 1; overflow-y: auto; min-height: 0;"><div style="display:flex; flex-direction:column; gap:10px; padding-bottom:20px;">${listHtml}</div></div>`;
    }

    container.innerHTML = buttonHtml + contentHtml;

    // 事件绑定
    container.querySelectorAll('.sect-task-card').forEach(card => {
        card.addEventListener('click', handleTaskToggle);
    });

    container.querySelectorAll('.accept-task-btn').forEach(btn => {
        btn.addEventListener('click', handleAcceptTask);
    });

    container.querySelectorAll('.abandon-task-btn').forEach(btn => {
        btn.addEventListener('click', handleAbandonTask);
    });

    container.querySelectorAll('.submit-task-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const taskId = e.currentTarget.dataset.taskId;
            handleTaskSubmission(taskId);
        });
    });

    // 【新增】绑定删除按钮点击事件
    container.querySelectorAll('.delete-sect-task-btn').forEach(btn => {
        btn.addEventListener('click', async (e) => {
            e.stopPropagation(); // 防止触发展开/收起
            const taskId = e.currentTarget.dataset.taskId;

            if (await showCustomConfirm('确定要删除这个宗门任务吗？')) {
                if (Array.isArray(currentState.sectData.tasks)) {
                    currentState.sectData.tasks = currentState.sectData.tasks.filter(t => t.id !== taskId);
                } else if (typeof currentState.sectData.tasks === 'object') {
                    // 兼容对象存储结构
                    for (const key in currentState.sectData.tasks) {
                        if (currentState.sectData.tasks[key].id === taskId) {
                            delete currentState.sectData.tasks[key];
                            break;
                        }
                    }
                }

                await saveCurrentState();
                // 重新渲染当前列表
                renderSectTasks(currentState.sectData.tasks, container);
                showDanmaku('任务已删除', 'success');
            }
        });
        // 添加鼠标悬停变色效果
        btn.addEventListener('mouseover', () => { btn.style.color = '#e57373'; });
        btn.addEventListener('mouseout', () => { btn.style.color = '#666'; });
    });

    if (canManage) {
        const addBtn = container.querySelector('#add-sect-task-btn');
        if (addBtn) {
            addBtn.addEventListener('click', openSectTaskCreator);
        }
    }
}


async function openSectTaskCreator() {
    const dialogContent = `
        <div id="sect-task-creator-form" style="display: flex; flex-direction: column; gap: 15px; text-align: left;">
            <input type="text" id="task-title-input" placeholder="任务标题" required>
            <textarea id="task-desc-textarea" placeholder="任务描述" rows="3"></textarea>
            <input type="text" id="task-reward-input" placeholder="任务奖励">
            <input type="text" id="task-punishment-input" placeholder="失败惩罚 (可选)">
            <input type="text" id="task-min-realm-input" placeholder="最低境界要求 (可选)">
        </div>
    `;

    const confirm = await showCustomDialog({
        title: '发布宗门新任务',
        message: dialogContent,
        buttons: [
            { text: '取消', value: () => false },
            { text: '确认发布', value: () => true, style: 'danger' } 
        ]
    });

    if (confirm) {
        const title = document.getElementById('task-title-input').value.trim();
        if (!title) {
            showCustomAlert('任务标题不能为空！');
            return;
        }

        const taskDesc = document.getElementById('task-desc-textarea').value.trim();
        const taskReward = document.getElementById('task-reward-input').value.trim();
        const taskPunishment = document.getElementById('task-punishment-input').value.trim();
        const taskMinRealm = document.getElementById('task-min-realm-input').value.trim();

        // 拼接成一个自然语言的动作描述
        let commandText = `我作为宗主（或高层），发布了一项新的宗门任务：\n- 标题: ${title}\n- 描述: ${taskDesc}\n- 奖励: ${taskReward}`;
        if (taskPunishment) {
            commandText += `\n- 惩罚: ${taskPunishment}`;
        }
        if (taskMinRealm) {
            commandText += `\n- 要求: ${taskMinRealm}`;
        }

        // 使用 addAction 添加到待执行指令队列
        addAction('publish_sect_task', { fullText: commandText });

        showToast('发布任务的指令已添加到待执行队列！', 'success');

        closeSectSystem(); 
    }
}



function renderSectPositions(positions, container) {
    if (!container || !currentState.sectData) return;
    const playerPosition = currentState.sectData.positions?.find(p => p.members?.includes('B1'));
    let canManage = false;
    if (playerPosition) {
        const superAdminTitles = ['宗主', '太上长老', '副宗主'];
        canManage = playerPosition.permissions?.includes('all') || 
                    playerPosition.permissions?.includes('manage_positions') ||
                    superAdminTitles.includes(playerPosition.title);
    }

    const formatPermissions = (permissions) => {
        if (!permissions || permissions.length === 0) return '无';
        if (permissions.includes('all')) return '全部权限';
        return permissions.join(', ');
    };

    let buttonHtml = '';
    if (canManage) {
        buttonHtml = `
            <div style="text-align: right; margin-bottom: 10px; flex-shrink: 0;">
                <button id="add-sect-position-btn" class="major-action-button small-font-btn"><i class="fas fa-plus"></i> 新增职位</button>
            </div>
        `;
    }

    let listContentHtml = '';
    if (!positions || positions.length === 0) {
        listContentHtml = '<p style="text-align: center; padding-top: 20px; opacity: 0.7;">宗门尚未设立职位。</p>';
    } else {
        const headerColumns = ['职位名称', '人数', '俸禄 (灵石/月)', '职责'];
        if (canManage) {
            headerColumns.push('操作');
        }

        listContentHtml += `
            <div class="sect-position-list-header" style="grid-template-columns: 2fr 1fr 1fr 2fr ${canManage ? '1fr' : ''};">
                ${headerColumns.map(h => `<span>${h}</span>`).join('')}
            </div>
        `;

        positions.forEach(p => {
            const currentCount = p.members ? p.members.length : 0;
            const maxCount = p.max || '不限';
            const isProtected = p.permissions?.includes('all');
            let actionsHtml = '';
            if (canManage) {
                if (isProtected) {
                    actionsHtml = '<span>-</span>';
                } else {
                    actionsHtml = `
                        <div class="sect-position-actions">
                            <button class="major-action-button small-font-btn set-salary-btn" data-position-name="${p.title}">
                                <i class="fas fa-coins"></i> 设置
                            </button>
                        </div>
                    `;
                }
            }

            listContentHtml += `
                <div class="sect-position-list-item" style="grid-template-columns: 2fr 1fr 1fr 2fr ${canManage ? '1fr' : ''};">
                    <span>${p.title}</span>
                    <span>${currentCount} / ${maxCount}</span>
                    <span>${p.salary || 0}</span>
                    <span style="text-align: left; padding-left: 10px;">${p.duties || formatPermissions(p.permissions)}</span>
                    ${actionsHtml}
                </div>
            `;
        });
    }

    container.innerHTML = `
        ${buttonHtml}
        <div style="flex-grow: 1; overflow-y: auto; min-height: 0;">
            ${listContentHtml}
        </div>
    `;

    if (canManage) {
        const addBtn = document.getElementById('add-sect-position-btn');
        if (addBtn) {
             addBtn.addEventListener('click', () => {
                 addToInput('为宗门新增一个职位');
                 closeSectSystem();
            });
        }
    }
}
function showSectBuildingInteractionPopup(buildingData, event) {
    const existingPopup = document.getElementById('sect-building-popup');
    if (existingPopup) {
        existingPopup.remove();
    }

    const popup = document.createElement('div');
    popup.id = 'sect-building-popup';
    Object.assign(popup.style, {
        position: 'fixed',
        minWidth: '250px',
        maxWidth: '300px',
        padding: '15px',
        background: 'rgba(26, 26, 26, 0.9)',
        backdropFilter: 'blur(5px)',
        border: '1px solid var(--primary-color)',
        borderRadius: '8px',
        color: 'var(--text-primary)',
        zIndex: '10005',
        boxShadow: '0 4px 20px rgba(0, 0, 0, 0.5)',
        fontSize: '0.9em'
    });

    let buttonsHtml = `
        <button class="interaction-btn" data-action="enter">进入</button>
        <button class="interaction-btn" data-action="view">查看</button>
    `;

    if (buildingData.effect && (buildingData.effect.includes('修炼') || buildingData.effect.includes('感悟'))) {
        buttonsHtml += `<button class="interaction-btn" data-action="cultivate">在此修炼</button>`;
    }

    popup.innerHTML = `
        <div style="font-weight: bold; font-size: 1.1em; color: var(--primary-color); margin-bottom: 8px;">${buildingData.name} (Lv.${buildingData.level})</div>
        <p style="margin: 0 0 12px; color: var(--text-secondary); border-top: 1px solid var(--separator-color); padding-top: 8px;">${buildingData.desc}</p>
        <div class="interaction-buttons" style="display:flex; gap: 8px;">
            ${buttonsHtml}
        </div>
    `;

    document.body.appendChild(popup);

    let left = event.clientX + 15;
    let top = event.clientY;

    const popupRect = popup.getBoundingClientRect();
    if (left + popupRect.width > window.innerWidth - 10) {
        left = event.clientX - popupRect.width - 15;
    }
    if (top + popupRect.height > window.innerHeight - 10) {
        top = window.innerHeight - popupRect.height - 10;
    }

    popup.style.left = `${left}px`;
    popup.style.top = `${top}px`;

    const closePopup = () => {
        popup.remove();
        document.removeEventListener('click', clickAwayHandler, true);
    };

    popup.querySelectorAll('.interaction-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            const action = btn.dataset.action;
            if (action === 'enter') {
                addToInput(`我决定进入 ${buildingData.name}。`);
            } else if (action === 'view') {
                addToInput(`我仔细查看了一下 ${buildingData.name} 的情况。`);
            } else if (action === 'cultivate') {
                addToInput(`我准备在 ${buildingData.name} 内闭关修炼。`);
            }
            closeSectSystem(); 
            closePopup(); 
        });
    });

    const clickAwayHandler = (e) => {
        if (!popup.contains(e.target)) {
            closePopup();
        }
    };

    setTimeout(() => document.addEventListener('click', clickAwayHandler, true), 0);
}

// 全局变量存储宗门地图实例
let activeSectMapViewer = null;

async function renderSectMap(mapData, container) {
    if (!container) return;
    const canvas = container.querySelector('canvas');
    if (!canvas) return;

    // 1. 检查数据有效性
    if (!mapData || !mapData.terrain || mapData.terrain.length === 0) {
        const ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        canvas.style.display = 'none';
        // 隐藏按钮
        const btnGroup = container.querySelector('div[style*="position: absolute"]');
        if (btnGroup) btnGroup.style.display = 'none';

        if (!container.querySelector('.no-map-msg')) {
            const msgDiv = document.createElement('div');
            msgDiv.className = 'no-map-msg';
            msgDiv.style.cssText = 'display:flex;justify-content:center;align-items:center;height:100%;color:#666;position:absolute;top:0;left:0;width:100%;pointer-events:none;';
            msgDiv.innerHTML = '暂无宗门地图数据<br>（请等待下一次宗门演化生成）';
            container.appendChild(msgDiv);
        }
        return;
    }

    // 2. 清理旧提示并显示界面元素
    const msg = container.querySelector('.no-map-msg');
    if (msg) msg.remove();
    canvas.style.display = 'block';
    const btnGroup = container.querySelector('div[style*="position: absolute"]');
    if (btnGroup) btnGroup.style.display = 'flex';

    // 3. 初始化或更新 SceneMapViewer 实例
    // 使用 setTimeout 确保在容器 display:block 且布局计算完成后再初始化，否则尺寸会不对
    setTimeout(() => {
        if (!activeSectMapViewer) {
            // 首次创建：实例化 SceneMapViewer (支持拖拽、缩放的核心类)
            // 第三个参数是 onSelect (移动), 第六个参数是 onElementClick (点击建筑/图标)
            activeSectMapViewer = new SceneMapViewer(
                canvas, 
                mapData, 
                null, // onSelectCallback (宗门地图暂不需要移动主角)
                false, // isWorldMap
                false, // isEditor
                (clickedItem, event) => {
                    // 【新增】宗门地图点击回调
                    if (clickedItem && clickedItem.name) {
                        // 尝试在 sectData.territory 中查找对应的建筑数据
                        const territory = currentState.sectData?.territory || {};
                        let buildingData = territory[clickedItem.name];

                        // 构造一个基础数据对象，如果找不到详细数据则使用默认值
                        const displayData = {
                            name: clickedItem.name,
                            level: buildingData ? buildingData.level : 0,
                            desc: buildingData ? (buildingData.description || buildingData.effect || '暂无描述') : '暂无详细信息'
                        };

                        // 调用已有的建筑弹窗函数
                        showSectBuildingInteractionPopup(displayData, event);
                    }
                }
            );


            // 绑定按钮事件
            const resetBtn = document.getElementById('sect-map-reset-btn');
            const inBtn = document.getElementById('sect-map-in-btn');
            const outBtn = document.getElementById('sect-map-out-btn');

            if (resetBtn) resetBtn.onclick = (e) => { e.stopPropagation(); activeSectMapViewer.resetView(); };
            if (inBtn) inBtn.onclick = (e) => { e.stopPropagation(); activeSectMapViewer.zoom(1.2); };
            if (outBtn) outBtn.onclick = (e) => { e.stopPropagation(); activeSectMapViewer.zoom(0.8); };

        } else {
            // 非首次：更新数据并重置视图
            activeSectMapViewer.setConfig(mapData);
            activeSectMapViewer.resize(); // 强制重新计算容器尺寸
            // 如果你想保留用户的缩放位置，可以注释掉下面这行；如果想每次切回来都居中，则保留
            // activeSectMapViewer.resetView(); 
            activeSectMapViewer.draw();
        }
    }, 10);
}

function renderSectTerritory(territory, container) {

    if (!container) return;
    const sectLevel = currentState.sectData.level || 1;
    const playerPosition = currentState.sectData.positions?.find(p => p.members?.includes('B1'));
    let canManage = false;
    if (playerPosition) {
        const superAdminTitles = ['宗主', '太上长老', '副宗主'];
        canManage = playerPosition.permissions?.includes('all') || superAdminTitles.includes(playerPosition.title);
    }

    const headerHtml = `
        <div class="sect-card" style="margin-bottom:15px; background:rgba(140, 120, 83, 0.1); border-color:#8c7853;">
            <div style="text-align:center; color:#ffd700; font-weight:bold;">宗门等级 Lv.${sectLevel}</div>
            <div style="text-align:center; font-size:0.85em; color:#aaa;">全员全属性加成 +${sectLevel}%</div>
        </div>
    `;

    container.innerHTML = headerHtml;

    const gridContainer = document.createElement('div');
    gridContainer.className = 'sect-territory-grid';
    container.appendChild(gridContainer);

    if (Object.keys(territory).filter(k => k !== 'map').length === 0) {
        gridContainer.innerHTML = '<p style="grid-column: 1 / -1; text-align: center; opacity: 0.7;">宗门尚未建立任何建筑。</p>';
