    Object.keys(territory).forEach(key => {
        if (key === 'map') return;

        const building = territory[key];
        const card = document.createElement('div');
        card.className = 'sect-card sect-building-card';

        const upgradeCost = getBuildingUpgradeCost(building.level, key);
        let actionHtml = '';

        if (canManage) {
            if (upgradeCost) {
                const canAfford = (currentState.sectData.funds || 0) >= upgradeCost.funds;
                const icon = building.level > 0 ? 'fa-arrow-up' : 'fa-hammer';
                const text = building.level > 0 ? '升级' : '建造';
                const color = canAfford ? '#66bb6a' : '#e57373';

                actionHtml = `
                    <div class="sect-building-upgrade-req">
                        <span>需 ${upgradeCost.funds} 灵石</span>
                    </div>
                    <button class="major-action-button small-font-btn sect-upgrade-btn" data-building-key="${key}" ${canAfford ? '' : 'disabled'}>
                        <i class="fas ${icon}"></i> ${text}
                    </button>
                `;
            } else {
                actionHtml = `<div class="sect-building-upgrade-req" style="color: #ffd700;">已满级</div>`;
            }
        } else {
             actionHtml = `<div class="sect-building-upgrade-req">&nbsp;</div>`;
        }

        const buildingName = building.name || key;

        card.innerHTML = `
            <i class="fas ${building.icon || 'fa-home'} sect-building-icon"></i>
            <div class="sect-building-name">${buildingName}</div>
            <div class="sect-building-level">Lv.${building.level || 0}</div>
            <div class="sect-building-desc">${building.description || '暂无描述。'}</div>
            <div class="sect-building-effect">${building.effect || ''}</div>
            ${actionHtml}
        `;

        card.addEventListener('click', (event) => {
            if (event.target.closest('button')) {
                return;
            }
            const buildingDataWithName = { ...building, name: buildingName };
            showSectBuildingInteractionPopup(buildingDataWithName, event);
        });

        gridContainer.appendChild(card);
    });

    gridContainer.querySelectorAll('.sect-upgrade-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            upgradeBuilding(btn.dataset.buildingKey);
        });
    });
}

async function loadWorldEvolutionSettings() {
    const defaultConfig = {
