        diffTrackingFields: [
            { id: 'diff-realm', label: '境界', key: '2', subkey: 'realm', type: 'split', enabled: true },
            { id: 'diff-identity', label: '身份', key: '2', subkey: 'identity', type: 'split', enabled: true },
