function handleSectWarehouseItemClick(event) {
    const slot = event.target.closest('.sect-warehouse-slot');
    if (!slot) return;

    if (event.target.closest('.sect-exchange-btn')) {
        return; 
    }

    const itemId = slot.dataset.itemId;
    if (!itemId) {
        showCustomAlert("此物品数据已损坏，无法查看详情。");
