function renderPlayerAttributes() {
    attributesList.innerHTML = '';
    if (!playerDisplaySettings || (!playerDisplaySettings.defaultFields && !playerDisplaySettings.customFields)) {
        attributesList.innerHTML = '<li><span class="attr-label">请点击右侧齿轮配置</span></li>';
        return;
    }
    const playerRow = currentState['0'] ? currentState['0']['B1'] : null;
    if (!playerRow) {
        attributesList.innerHTML = '<li><span class="attr-label">玩家数据加载中...</span></li>';
        return;
    }
    const remarks = parseRemarksString(playerRow['9']);
    const fragment = document.createDocumentFragment();
    const { totalBonuses: bonuses } = calculateTotalBonuses();
    const formatNum = (n) => {
        if (Math.abs(n) >= 10000) return (n / 10000).toFixed(1) + '万';
        return n;
    };
    const createListItemWithBonus = (label, value, bonusValue) => {
        const li = document.createElement('li');
        let bonusHtml = '';
        if (bonusValue > 0) bonusHtml = ` <span class="attr-bonus" style="color:#50fa7b;">(+${formatNum(bonusValue)})</span>`;
        else if (bonusValue < 0) bonusHtml = ` <span class="attr-penalty">(${formatNum(bonusValue)})</span>`;
        li.innerHTML = `<span class="attr-label">${label}:</span><span class="attr-value">${value ?? '无'}${bonusHtml}</span>`;
        fragment.appendChild(li);
    };
    if (playerDisplaySettings.defaultFields) {
        playerDisplaySettings.defaultFields.forEach(field => {
            if (field.isEnabled) {
                let value;
                let bonusValue = 0;
                let skipDefaultRender = false;
                switch (field.key) {
                    case 'linggen':
                        value = remarks['灵根'];
                        break;
                    case 'hp':
                        skipDefaultRender = true;
                        const li = document.createElement('li');
                        const baseHp = currentPlayerData.detailedAttributes['血量'] || {
                            current: 0,
                            max: 0
                        };
                        const bonusHp = bonuses['血量'] || 0;
                        const totalCurrent = baseHp.current + bonusHp;
                        const totalMax = baseHp.max + bonusHp;
                        let bonusHtml = '';
                        if (bonusHp > 0) bonusHtml = ` <span class="attr-bonus" style="color:#50fa7b;">(+${formatNum(bonusHp)})</span>`;
                        li.innerHTML = `<span class="attr-label">血量:</span><span class="attr-value" title="${totalCurrent}/${totalMax}">${totalCurrent}/${totalMax}${bonusHtml}</span>`;
                        fragment.appendChild(li);
                        break;
                    case 'gender':
                        value = (playerRow['1'] || '|').split('|')[1];
                        break;
                    case 'age':
                        value = remarks['年龄'];
                        break;
                    case 'shouyuan':
                        value = remarks['寿元'];
                        bonusValue = bonuses['寿元'] || 0;
                        break;
                    case 'realm':
                        value = (playerRow['2'] || '|').split('|')[0];
                        break;
                    case 'shanE':
                        value = remarks['善恶值'];
                        break;
                    case 'location':
                        {
                            const fullLocationString = (currentState['4'] ?.[0]?.['0'] || '');
                            const firstSlashIndex = fullLocationString.indexOf('/');
                            value = (firstSlashIndex !== -1) ? fullLocationString.substring(firstSlashIndex + 1) : '未知';
                            break;
                        }
                    case 'spiritStones':
                        value = playerRow['26'] || '0';
                        break;
                }
                if (!skipDefaultRender) createListItemWithBonus(field.label, value, bonusValue);
            }
        });
    }
    if (playerDisplaySettings.customFields) {
        playerDisplaySettings.customFields.forEach(field => {
            if (field.isEnabled && typeof field.column === 'number') {
                let value = (field.column === 9) ? (remarks[field.variableName] || '未定义') : playerRow[String(field.column)];
                createListItemWithBonus(field.label, value, 0);
            }
        });
    }
    attributesList.innerHTML = '';
    if (fragment.children.length > 0) attributesList.appendChild(fragment);
    else attributesList.innerHTML = '<li><span class="attr-label">无显示项,请配置</span></li>';
}


