async function handleTaskSubmission(taskId) {
    // 1. 获取任务完整数据
    const sectData = currentState.sectData;
    let task = null;

    if (Array.isArray(sectData.tasks)) {
        task = sectData.tasks.find(t => t.id === taskId);
    } else {
        // 兼容对象格式
        Object.values(sectData.tasks).forEach(t => { if(t.id === taskId) task = t; });
    }

    if (!task) {
        showCustomAlert('任务数据已过期或不存在。');
        return;
    }

    // 2. 构造包含完整数据的指令文本
    // 重点：将奖励数据和任务ID完整发给AI，防止AI产生幻觉生成错误的奖励
    let rewardsDesc = '';
    if (task.rewards) {
        if (task.rewards.contribution) rewardsDesc += `${task.rewards.contribution}贡献, `;
        if (task.rewards.items) rewardsDesc += task.rewards.items.map(i => `${i.name}x${i.count}`).join(', ');
    }

    const command = `我前往任务堂，提交任务【${task.title}】(ID:${task.id})。\n【系统数据校验】\n- 状态: 已完成(待提交)\n- 应发奖励: ${rewardsDesc || task.reward}\n请根据此数据结算任务，发放奖励并更新我的贡献点。`;

    // 3. 发送指令 (改为静默 Action)
    // 使用自定义类型 'submit_sect_task' 或复用 'publish_sect_task' 的通用逻辑
    // 这里我们添加一个新的 case 到 addAction，或者直接用通用方式
    addAction('submit_sect_task', { fullText: command }, {}, true); // true 表示静默

    // 4. 本地预更新状态 (提升体验，防止重复提交)
    task.status = 'completed'; 
    task.readyToSubmit = false;
    await saveCurrentState();

    closeSectSystem();
    showDanmaku('任务提交请求已发送...', 'success');
}


async function handleAbandonTask(event) {
    event.stopPropagation();
    const btn = event.target.closest('.abandon-task-btn');
    if (!btn) return; // 安全检查
    const taskId = btn.dataset.taskId;
    const taskTitle = btn.dataset.taskTitle;

    if (await showCustomConfirm(`确定要放弃任务 “${taskTitle}” 吗？\n放弃后任务进度将丢失，且可能会有宗门惩罚。`)) {
        const sectData = currentState.sectData;
        let taskToUpdate = null;

        // 查找任务
        if (Array.isArray(sectData.tasks)) {
            taskToUpdate = sectData.tasks.find(t => t && t.id === taskId);
        } else if (typeof sectData.tasks === 'object') {
            Object.values(sectData.tasks).forEach(t => {
                if (t.id === taskId) taskToUpdate = t;
            });
        }

        if (taskToUpdate) {
            // 重置任务状态
            taskToUpdate.status = 'available';
            taskToUpdate.assignee = null;
            taskToUpdate.progress = ''; // 清空进度

            await saveCurrentState();
            renderSectTasks(sectData.tasks, document.getElementById('sect-pane-tasks'));

            // 发送放弃指令给AI
            addAction('abandon_task', { title: taskTitle }, {}, true);
            showDanmaku('已放弃任务', 'info');
        }
    }
}

function handleTaskToggle(event) {
    const taskCard = event.target.closest('.sect-task-card');
