    if (!taskCard || event.target.closest('.accept-task-btn') || event.target.closest('.abandon-task-btn')) {
        return; 
    }
    const body = taskCard.querySelector('.sect-task-body');
    const arrow = taskCard.querySelector('.sect-task-arrow');
    const isHidden = body.style.display === 'none' || body.style.display === '';

    if (isHidden) {
        body.style.display = 'block';
        if (arrow) arrow.style.transform = 'rotate(90deg)';
    } else {
        body.style.display = 'none';
        if (arrow) arrow.style.transform = 'rotate(0deg)';
    }
}

async function handleAcceptTask(event) {
    event.stopPropagation();
    const btn = event.target.closest('.accept-task-btn');
    const title = btn.dataset.taskTitle;
    const taskId = btn.dataset.taskId;
    const reqRealm = btn.dataset.reqRealm;
    const isMet = btn.dataset.isMet === 'true';

    const performAction = async () => {
        const sectData = currentState.sectData;
        if (sectData && sectData.tasks) {
            let taskToUpdate;
            if (Array.isArray(sectData.tasks)) {
                taskToUpdate = sectData.tasks.find(t => t && t.id === taskId);
            } else if (typeof sectData.tasks === 'object' && sectData.tasks !== null) {
                const taskKey = Object.keys(sectData.tasks).find(k => sectData.tasks[k] && sectData.tasks[k].id === taskId);
                if (taskKey) {
                    taskToUpdate = sectData.tasks[taskKey];
                }
            }

            if (taskToUpdate) {
                taskToUpdate.status = 'in-progress';
                taskToUpdate.assignee = 'B1';
                await saveCurrentState();
                renderSectTasks(sectData.tasks, document.getElementById('sect-pane-tasks'));
            }
        }

        // 【修复】携带完整任务数据给 AI，防止幻觉
        const taskDataForAI = taskToUpdate ? {
            id: taskToUpdate.id,
            title: taskToUpdate.title,
            desc: taskToUpdate.desc || taskToUpdate.description,
            reward: taskToUpdate.reward || (taskToUpdate.rewards ? JSON.stringify(taskToUpdate.rewards) : '无'),
            punishment: taskToUpdate.punishment,
            minRealm: taskToUpdate.minRealm,
            type: taskToUpdate.type
        } : { title: title };

        // 构造更详细的指令文本
        const detailedCommand = `我决定接取宗门任务【${taskDataForAI.title}】。\n(系统备注: ID=${taskDataForAI.id}, 描述="${taskDataForAI.desc}", 奖励=${taskDataForAI.reward})`;

        // 使用自定义类型的 addAction 以便传递完整文本，同时保持静默
        // 这里虽然 type 还是 accept_task，但我们在 data 中放入 fullText，并在 switch 中处理
        addAction('accept_task', { 
            title: title,
            fullText: detailedCommand 
        }, {}, true);

        closeSectSystem();
    };


    if (!isMet) {
        const playerRealm = (currentPlayerData.realm || '凡人').split('|')[0];
        const confirm = await showDangerConfirm(reqRealm, playerRealm);
        if (confirm) {
            await performAction();
        }
    } else {
        await performAction();
    }
}

