async function handleNpcAutoImageGen(charId, prompt) {
    if (typeof eventEmit !== 'function') {
        console.error('自动生图错误: 未找到前端助手通信接口 (eventEmit)。');
        return;
    }

    const width = npcDisplaySettings.npcImageWidth || 512;
    const height = npcDisplaySettings.npcImageHeight || 768;

    const requestId = `npc_${charId}_${Date.now()}`;
    const requestData = { id: requestId, prompt, width, height, type: 1 };

    const charName = characterDatabase[charId]?.name || '新人物';
    let statusDanmaku = showDanmaku(`正在自动生成 ${charName} 的形象...`, 'status', null, true);

    if (statusDanmaku) {
        activeImageGenDanmaku.set(requestId, statusDanmaku);
    }

    try {
        await eventEmit('generate-image-request', requestData);
        await eventEmit('generate_image_request', requestData);
    } catch (e) {
        console.error(`为 ${charName} 发送生图请求失败: `, e);
        if (statusDanmaku) statusDanmaku.remove();
        activeImageGenDanmaku.delete(requestId);
    }
}

let backgroundGenApiController = null; 

async function extractAndGenerateBackground(text) {

    if (!chatBackgroundSettings.autoGen) {
        return;
    }

    let promptForApi = '';
    let statusDanmaku = null;
    let methodUsed = '';

    const { apiUrl, apiKey, apiModel, apiPromptTemplate } = chatBackgroundSettings;
    if (apiUrl && apiKey && apiModel && apiPromptTemplate) {
        methodUsed = 'API';
        const snapshotContentForPrompt = generatePrettySnapshotForAI(); 
        const combinedJsonContextData = backgroundJsonFiles
            .filter(file => file.active)
            .map(file => file.content)
            .join('\n\n');

        const promptForPromptGeneration = apiPromptTemplate
            .replace(/\$\{text\}/g, text)
            .replace(/\$\{state_snapshot\}/g, snapshotContentForPrompt)
            .replace(/\$\{json_context\}/g, combinedJsonContextData);

        try {
            console.log("正在请求背景图生成API以提取关键词...");
            const generatedImagePrompt = await genericApiCall(apiUrl, apiKey, apiModel, promptForPromptGeneration);

            if (generatedImagePrompt && generatedImagePrompt.trim()) {
                promptForApi = generatedImagePrompt.trim().replace(/["'\n]/g, '');
                lastGeneratedPrompt = promptForApi; 
                showDanmaku('AI关键词提取成功', 'success');
            } else {
                console.warn("背景图关键词生成API返回为空。");
            }
        } catch (error) {
            console.error("通过API生成背景图关键词时出错:", error);
            showDanmaku(`背景图关键词API失败: ${error.message}`, 'error');
        }
    } 

    if (!promptForApi && chatBackgroundSettings.aiGenRegex) {
        methodUsed = methodUsed || '正则';
        try {
            const { pattern, flags } = parseRegexString(chatBackgroundSettings.aiGenRegex);
            const regex = new RegExp(pattern, flags);
            const match = text.match(regex);
            if (match && match[1]) {
                promptForApi = match[1].trim();
                lastGeneratedPrompt = promptForApi;
            }
        } catch (e) {
            console.error('AI生图正则解析失败:', e);
        }
    }

    if (!promptForApi) {
        const bgMatch = text.match(/<pic\s+prompt="([^"]+)"\s*\/?>/i);
        if (bgMatch && bgMatch[1]) {
            promptForApi = bgMatch[1].trim();
            lastGeneratedPrompt = promptForApi;
            methodUsed = methodUsed || '内置正则';
        }
    }

    if (!promptForApi) {
        console.log("未能在正文中找到任何可用于生成背景的关键词。");
        return;
    }

    console.log(`背景生成已触发，使用方法: ${methodUsed}，关键词: ${promptForApi.substring(0, 50)}...`);

    backgroundGenApiController = new AbortController();

    try {
        statusDanmaku = showDanmaku(`正在自动生成背景 (${methodUsed})...`, 'status', backgroundGenApiController, true);
        await handleAIGenRequest(promptForApi, true, statusDanmaku);
        backgroundGenApiController = null;

    } catch (error) {
        if (error.name !== 'AbortError') {
            console.error('自动背景图片生成失败:', error);
            showDanmaku('自动背景图片生成失败', 'error');
        }
        if (statusDanmaku) statusDanmaku.remove();
        backgroundGenApiController = null;
    }
}

