function upgradeSect() {
    const sectData = currentState.sectData;
    if (!sectData) return;

    const cost = getSectUpgradeCost(sectData.level);
    if (!cost) {
        showToast("宗门已达最高等级！", "info");
        return;
    }

    if ((sectData.prestige || 0) < cost.prestige || (sectData.funds || 0) < cost.funds) {
        showToast("宗门声望或资金不足，无法晋升！", "error");
        return;
    }

    sectData.level = cost.level;
    sectData.prestige -= cost.prestige;
    sectData.funds -= cost.funds;

    updateSectHeaderStats();
    saveCurrentState();

    aiNotificationQueue.push(`【系统提示】我操作界面将宗门提升到了 ${cost.level} 级，消耗了 ${cost.prestige} 声望和 ${cost.funds} 灵石。请在返回的世界状态中体现出宗门实力（尤其是全属性加成）的增长。`);

    document.querySelector('.sect-tab[data-tab="info"]').click();
    showToast(`宗门成功晋升至 ${cost.level} 级！`, "success");
}

