document.getElementById('import-sect-evolution-presets-btn').addEventListener('click', () => {
    const importInput = document.createElement('input');
    importInput.type = 'file';
    importInput.accept = '.json';
    importInput.style.display = 'none';

    importInput.onchange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = async (event) => {
            try {
                const presetsData = await dbGet(SECT_EVOLUTION_PRESETS_KEY) || { presets: [], activePresetId: null };
                const importedPresets = JSON.parse(event.target.result);

                if (!Array.isArray(importedPresets)) {
                    throw new Error("导入文件格式不正确，应为预设数组。");
                }

                let addedCount = 0;
                let overwrittenCount = 0;

                for (const preset of importedPresets) {
                    if (preset && preset.name && preset.rules) {
                        const existingIndex = presetsData.presets.findIndex(p => p.name === preset.name);
                        if (existingIndex > -1) {
                            if (await showCustomConfirm(`已存在同名宗门预设 "${preset.name}"，是否覆盖？`)) {
                                presetsData.presets[existingIndex] = { ...preset, id: presetsData.presets[existingIndex].id };
                                overwrittenCount++;
                            }
                        } else {
                            presetsData.presets.push({ id: preset.id || crypto.randomUUID(), ...preset });
                            addedCount++;
                        }
                    }
                }

                if (addedCount > 0 || overwrittenCount > 0) {
                    await dbSet(SECT_EVOLUTION_PRESETS_KEY, presetsData);
                    await manageSectEvolutionPresets();
                    await showCustomAlert(`导入完成！\n新增 ${addedCount} 个，覆盖 ${overwrittenCount} 个。`);
                } else {
                    showDanmaku('没有新的内容被导入。', 'info');
                }

            } catch (err) {
                await showCustomAlert(`导入失败: ${err.message}`);
            } finally {
                e.target.value = '';
            }
        };
        reader.readAsText(file);
    };
    document.body.appendChild(importInput);
    importInput.click();
    document.body.removeChild(importInput);
});

document.getElementById('export-sect-evolution-presets-btn').addEventListener('click', async () => {
