    document.getElementById('manual-deep-summary-btn').addEventListener('click', async () => {
        const archive = await db.archives.get(currentArchiveName);
        if (!archive) return;

        // 筛选出纯净的正文日志用于计算层数
        const validChatLogs = archive.data.logs.filter(log => 
            !log.isDeepSummary && 
            !log.isSnapshot && 
            !log.isUndoSnapshot && 
            !log.content.includes('<h4>天道初启</h4>') && 
            !log.isGhost
        ); 

        const totalCount = validChatLogs.length;
        if (totalCount === 0) {
            await showCustomAlert("当前没有可总结的剧情记录。");
            return;
        }

        // 弹窗询问范围
        const rangeInput = await showCustomPrompt(
            `当前有效剧情共 ${totalCount} 层。\n请指定要合并的范围 (格式: 起始层-结束层)\n\n注意：合并后这部分正文将消失，仅保留总结。`, 
            `1-${Math.min(100, totalCount)}`
        );

        if (rangeInput) {
            // 处理全角符号
            const parts = rangeInput.replace('，', '-').split(/[-–—]/); 
            if (parts.length === 2) {
                const start = parseInt(parts[0].trim());
                const end = parseInt(parts[1].trim());

                if (!isNaN(start) && !isNaN(end) && start <= end && start > 0) {
                     document.getElementById('segmented-memory-overlay').classList.remove('visible');
                     // 调用核心函数，传入 range
                     checkAndRunLayeredSummary(true, { start, end });
                } else {
                     showCustomAlert("输入的范围格式无效，请输入例如 1-50 的数字格式。");
                }
            } else {
                 showCustomAlert("格式错误，请使用横杠分隔起始和结束层数。");
            }
        }
    });


