        let text = activeLogEntry.textContent;
        if (activeLogEntry.classList.contains('user')) {
            text = text.replace(/^> /, '');
        }
        navigator.clipboard.writeText(text).then(() => showCustomAlert('消息已复制!')).catch(err => {
            console.error('复制失败:', err);
            showCustomAlert('复制失败');
        });
        hideContextMenu();
