    // --- 1. 更新：灵兽资质配置 (8阶) ---
    const BEAST_APTITUDE_CONFIG = [
        { name: '凡品', max: 100, color: '#b0bec5' },       // 灰/白
        { name: '灵品', max: 300, color: '#66bb6a' },       // 绿
        { name: '玄品', max: 600, color: '#4fc3f7' },       // 蓝
        { name: '地品', max: 1000, color: '#ba68c8' },      // 紫
        { name: '天品', max: 2500, color: '#ffd700' },      // 金
